window.allTests = window.allTests || {};

window.allTests["klasik_u3_bilim_1"] = [
    {
        soru: "<i>\"Osmanlı medreseleri, vakıf sistemi aracılığıyla finanse edilir ve sultanlar ile vezirlerin himayesinde kurulurdu. Müfredat İslam hukukunu, kelam ilmini, mantık ve filoloji derslerini kapsıyordu. Öğrenciler, Sahn-ı Seman gibi yüksek düzeyli medreselere geçmeden önce alt düzey medreselerde eğitimlerini tamamlamak zorundaydı.\"</i><br><br><b>Bu metinden hareketle Osmanlı medrese sisteminin finansman modeli ile eğitim hiyerarşisi arasındaki ilişkiyi açıklayınız. Vakıf kurumunun bu sistemdeki işlevini değerlendiriniz.</b>",
        cevap: "Doğru bir yanıt şu unsurları içermelidir: Osmanlı medreselerinin vakıf sistemiyle finanse edilmesi, devlet bütçesinden bağımsız ancak sultan/vezir denetiminde bir yapıyı ortaya koyuyordu. Vakıflar; medresenin fiziksel varlığını, müderrislerin maaşlarını ve öğrencilerin iaşesini karşılıyordu. Hiyerarşi açısından öğrenciler basitten karmaşığa doğru seyreden bir eğitim sürecinden geçiyordu; Sahn-ı Seman ise bu piramittin zirvesini oluşturuyordu. Bu yapının önemi: Vakıf finansmanı siyasi dalgalanmalardan görece bağımsız bir eğitim sürekliliği sağlıyordu. Sultan ve vezirlerin medrese kurması ise hem dini prestij hem de siyasi meşruiyet kazandırma stratejisiydi. Öğrenci, yeterlilik kanıtlamadan üst medreseye geçemediğinden akademik bir kalite kontrol mekanizması da mevcuttu. Öğrenci, vakfın sadece mali değil kültürel-kurumsal bir devamlılık aracı olduğunu vurgulamalıdır."
    },
    {
        soru: "<i>\"Mimar Sinan'ın Süleymaniye Külliyesi, yalnızca bir ibadet mekanı değil; medrese, darüşşifa, imaret ve kervansarayı bir arada barındıran kapsamlı bir kentsel kompleksti. Bu yapı, Osmanlı sultanının hem dinî hem de sosyal hizmet alanındaki otoritesini mimari biçimde ifade ediyordu.\"</i><br><br><b>Metne göre Osmanlı külliyesinin işlevsel çeşitliliğini açıklayınız. Bu çeşitliliğin Osmanlı devlet anlayışıyla ilişkisini yorumlayınız.</b>",
        cevap: "Doğru yanıt şunları kapsamalıdır: Külliye, tek bir dini işlev değil; eğitim (medrese), sağlık (darüşşifa), beslenme-barınma (imaret, kervansaray) ve ibadet (cami) gibi birden fazla toplumsal hizmeti tek çatı altında sunmaktadır. Devlet anlayışıyla ilişki: Osmanlı padişahı yalnızca siyasi-askeri bir lider değil, tebaasının refahından sorumlu bir 'koruyucu sultan' imgesi taşıyordu. Külliye bu imgeyi somutlaştırıyordu. Aynı zamanda vakıf aracılığıyla kurulan külliye, sultanın servetini halka yeniden dağıtma pratiğini temsil ederek meşruiyeti pekiştiriyordu. Öğrenci; külliyenin 'devlet-toplum-din' üçgenini mimari biçimde ifade ettiğini, Osmanlı yönetim felsefesinin somut bir tezahürü olduğunu analiz etmelidir."
    },
    {
        soru: "<i>\"Osmanlı saray çevresinde hat sanatı, yalnızca bir yazı biçimi olmaktan öte, bir statü göstergesi ve entelektüel birikimin ifadesiydi. Hattatlar, kadıların ve ulemanın da dahil olduğu geniş bir toplumsal kesimin saygısını kazanırdı. Hat eserlerinin koleksiyonculuğu, dönemin kültürel değerlerinin bir yansımasıydı.\"</i><br><br><b>Metinden hareketle hat sanatının Osmanlı toplumundaki sosyal işlevini açıklayınız. Hat sanatının statü göstergesi olması ile Osmanlı eğitim-kültür anlayışı arasında nasıl bir bağlantı kurulabilir?</b>",
        cevap: "Doğru yanıt şunları içermelidir: Hat sanatı Osmanlı toplumunda salt estetik değil, sosyal prestij ve entelektüel kimlik göstergesi olarak işlev görüyordu. Hattat olmak ya da hat eserlerine sahip olmak, kişinin eğitimine ve kültürel birikimine işaret ediyordu. Eğitim bağlantısı: Medrese eğitiminde Arap harflerinin öğretilmesi ve Kuran'ın doğru yazımına verilen önem, hattı doğrudan dini-entelektüel bir pratikle ilişkilendiriyordu. Ulema ve kadıların hattat saygısı, bilgi ile sanatın Osmanlı'da bütüncül bir kimlik oluşturduğunu gösterir. Öğrenci; koleksiyonculuğun kültürel sermayeyi somutlaştırma aracı olduğunu, sanatın siyasi-toplumsal işlevini ve Osmanlı eğitimindeki estetik boyutunu irdelemelidir."
    },
    {
        soru: "<i>\"Osmanlı astronomları, İslam dünyasının birikimini aktarmakla yetinmeyip bu mirasa özgün katkılarda bulundular. Takiyüddin er-Rasıt'ın İstanbul rasathanesi, 16. yüzyıl sonlarında dönemin en gelişmiş gözlem araçlarına sahipti. Ancak rasathane, kısa süre sonra ulema ve vezir baskısıyla yıktırıldı; bu durum Osmanlı bilim hayatındaki gerilimi gözler önüne serer.\"</i><br><br><b>Metni analiz ederek Osmanlı bilim ortamındaki 'ilerleme' ile 'kısıtlama' arasındaki çelişkiyi tartışınız. Rasathanenin yıktırılmasını hangi tarihsel ve kurumsal etkenlerle açıklayabilirsiniz?</b>",
        cevap: "Doğru yanıt şunları kapsamalıdır: İlerleme boyutu: Osmanlı'nın yalnızca İslam bilimini nakletmediği, Takiyüddin örneğinde görüldüğü üzere özgün gözlem kapasitesine sahip olduğu anlaşılmaktadır. Bu, Osmanlı'nın 16. yüzyılda bilimsel rekabete dahil olma iradesini gösterir. Kısıtlama boyutu: Rasathanenin yıkılması, gözlem faaliyetinin uğursuzlukla ilişkilendirilmesi, kaderin keşfedilemeyeceği argümanı ve siyasi çıkarların bilimsel kurumu tasfiye etmesi gibi etkenlerle açıklanabilir. Kurumsal gerilim: Osmanlı'da bilim, ulemadan bağımsız bir kurum kimliği kazanamadı. Devlet himayesindeki bilimsel faaliyetler, dini-siyasi aktörlerin onayına muhtaçtı. Öğrenci; bu yapıyı 'bilimsel özerklik' kavramı üzerinden sorgulayarak Osmanlı bilim kurumlarının kırılganlığını analiz etmelidir."
    },
    {
        soru: "<i>\"Mustafa Ali, Gelibolulu bir şair ve tarihçi olarak entelektüel birikimini devlet hizmetine sunmak istedi; ancak karşılaştığı patronaj eksikliği ve atama güçlükleri, dönemin bürokrasisindeki sistemik sorunları yansıtıyordu. Ali'nin eserleri, eleştirel bir perspektifle Osmanlı toplumunun kültürel ve ahlaki dönüşümünü sorgulamaktadır.\"</i><br><br><b>Mustafa Ali örneğinden hareketle 16. yüzyıl sonu Osmanlı dünyasında entelektüelin devlet ile ilişkisini değerlendiriniz. Patronaj sisteminin bilim ve edebiyat üretimi üzerindeki etkilerini açıklayınız.</b>",
        cevap: "Doğru yanıt şunları içermelidir: Entelektüel-devlet ilişkisi: Osmanlı'da bilgi ve sanat üretimi büyük ölçüde devlet patronajına bağımlıydı. Sultanlar, vezirler ve beyler; şair ve tarihçileri himaye etmeden onların hem geçimini hem de eserlerinin dağıtım ağını sağlıyordu. Mustafa Ali örneği: Patronaj bulamayan entelektüelin üretkenliği sekteye uğrar ya da eleştirel bir çizgiye kayar. Ali'nin eleştirel eserleri, himaye edilememenin yarattığı serbest bir düşünce alanına da işaret eder. Sistemik sorunlar: 16. yüzyıl sonunda bürokraside rüşvet ve torpil yaygınlaşmıştı; bu durum liyakatin görmezden gelinmesine yol açıyordu. Öğrenci; patronaj sisteminin sanat/bilim üretimini hem mümkün kıldığını hem de kontrol altında tuttuğunu, iktidar-bilgi ilişkisini 'patronaj' kavramı etrafında analiz etmelidir."
    },
    {
        soru: "<i>\"Sinan, mimarisinde Bizans ve Selçuklu mirasını Osmanlı estetik anlayışıyla sentezledi. Selimiye Camii'nin merkezi kubbe sistemi, teknik açıdan Ayasofya'yı aşmayı hedefliyordu. Bu rekabetçi yaklaşım, Osmanlı mimarlarının tarihsel miras karşısındaki özgüvenli tutumunu göstermektedir.\"</i><br><br><b>Metne göre Sinan'ın mimari anlayışında sentez ve rekabet unsurlarının nasıl bir arada var olduğunu açıklayınız. Bu tutumun Osmanlı kültürel kimliğinin inşasındaki rolünü değerlendiriniz.</b>",
        cevap: "Doğru yanıt şunları kapsamalıdır: Sentez boyutu: Sinan, Bizans'ın büyük kubbe mirasını (Ayasofya) ve Selçuklu'nun taş işçiliği ile kubbe geleneğini harmanlayarak Osmanlı mimarisine özgü bir dil yarattı. Bu sentez, Osmanlı'nın köklü medeniyetlerin mirasçısı olduğu iddiasını mimari üzerinden ifade etmektedir. Rekabet boyutu: Selimiye'nin Ayasofya'yı 'aşma' hedefi, Osmanlı'nın kendini Doğu Roma'nın varisi olarak konumlandırmasının önemli bir göstergesidir. Bu, kültürel özgüvenin ve imparatorluk kimliğinin mimari bir bildirisi olarak okunabilir. Kültürel kimlik: Osmanlı kimliği, mevcut mirasları reddetmek yerine dönüştürüp aşarak inşa edilmiştir; bu strateji, Osmanlı'nın evrensel medeniyet iddiasını güçlendirmiştir. Öğrenci bu analizi yapısal örneklerle desteklemelidir."
    },
    {
        soru: "<i>\"Fatih Sultan Mehmed'in saray çevresinde Batılı ve Doğulu bilginleri bir araya getirme çabası, Osmanlı entelektüel açılımının somut bir göstergesidir. Georgios Amirutzes ile İtalyan hümanistlerin İstanbul'a davet edilmesi, yalnızca bireysel merakla açıklanamaz; bu girişim, imparatorluğun evrensel bir medeniyet iddiasının parçasıydı.\"</i><br><br><b>Fatih döneminde gerçekleştirilen entelektüel açılımı metinden hareketle analiz ediniz. Bu dönemin Osmanlı kültür ve bilim anlayışının sonraki gelişimine katkısını değerlendiriniz.</b>",
        cevap: "Doğru yanıt şunları içermelidir: Entelektüel açılımın niteliği: Fatih, farklı dini ve kültürel geleneklerden gelen bilginleri sarayında bir araya getirerek çoğulcu bir entelektüel ortam oluşturdu. Bu ortamda coğrafya, felsefe, tarih ve tıp alanlarında önemli çalışmalar gerçekleşti. Evrensel medeniyet iddiası: Osmanlı, yalnızca İslam dünyasının lideri değil; tüm medeniyetlerin mirasçısı olma iddiasındaydı. Konstantinopolis'in fethinden sonra Bizans kültürel mirasını da üstlenme çabası bu iddianın somut bir yansımasıdır. Sonraki döneme katkısı: Fatih'in oluşturduğu entelektüel zemin, Kanuni dönemindeki kültürel ve mimari zirveye zemin hazırlamıştır. Öğrenci; açık kapı politikasının yalnızca merak değil, bilinçli bir imparatorluk ideolojisinin ürünü olduğunu analiz etmelidir."
    },
    {
        soru: "<i>\"Osmanlı divan şiiri, salt bir zevk ya da süsleme aracı değil; dönemin düşünsel ve toplumsal sorunlarını şifreli bir dille dışavuran bir iletişim ortamıydı. Şairlerin divanları, dönemin sosyal hiyerarşisi, değer yargıları ve çatışmaları hakkında tarihçiye değerli ipuçları sunar.\"</i><br><br><b>Divan şiirinin tarihsel kaynak olarak değerine ilişkin bu görüşü değerlendiriniz. Divan edebiyatının Osmanlı kültür ve eğitim ortamındaki işlevini açıklayınız.</b>",
        cevap: "Doğru yanıt şunları kapsamalıdır: Tarihsel kaynak değeri: Divan şiiri geleneksel tarih yazımının görmezden geldiği gündelik kaygıları, toplumsal gerilimleri ve değer çatışmalarını yansıtır. Şiirin alegorik ve metaforik dili, dönemin toplumsal yapısını dolaylı biçimde gözler önüne serer. Kültürel işlev: Divan şiiri, saray çevresinden medreseye ve kahvehaneye uzanan geniş bir coğrafyada toplumsal iletişim aracı işlevi gördü. Beyit ezberlemek, entelektüel bir beceri ve toplumsal kabul aracıydı. Eğitim boyutu: Medrese eğitiminde dil ve edebiyat derslerinin önemli bir parçasını oluşturan klasik şiir bilgisi, iyi bir Osmanlı bürokratının olmazsa olmaz donanımı sayılıyordu. Öğrenci, edebi metinlerin sıradan belgelerden farklı bilgiler sunduğunu, yoruma dayalı tarihçiliğin değerini savunmalıdır."
    },
    {
        soru: "<i>\"Osmanlılar'da medrese, yalnızca eğitim kurumu değil aynı zamanda bir kariyer basamağıydı. İstanbul medreselerinde yetişen müderrisler, zamanla kadılık ve müftülük gibi üst kademelere yükselebiliyordu. Bu sistemin yarattığı hiyerarşik yapı, ulemanın hem bilimsel hem de siyasi etkinliğini şekillendirdi.\"</i><br><br><b>Metinden hareketle Osmanlı medrese sisteminin hem eğitimsel hem de siyasi işlevini tartışınız. Bu sistemin ulemayı güçlü kılıp kılmadığını farklı açılardan değerlendiriniz.</b>",
        cevap: "Doğru yanıt şunları kapsamalıdır: Eğitimsel işlev: Medrese, İslam ilimleri başta olmak üzere mantık, matematik, dil ve hukuk alanlarında sistematik eğitim sunan kurumsal bir yapıydı. Müfredatın hiyerarşik düzenlenmesi, öğrencinin kademeli olarak uzmanlaşmasını sağlıyordu. Siyasi işlev: Medrese mezunları, yargı ve dini bürokraside kritik görevler üstleniyordu. Şeyhülislam, kadıasker ve müftü gibi makamlar medrese kökenli kişilerce dolduruluyor; bu da ulemanın devlet karar alma süreçlerinde belirleyici bir rol üstlenmesine olanak tanıyordu. Ulemanın gücü meselesi: Bir yanda ulema güçlüdür (rasathane kararı, siyasi fetva verme yetkisi); öte yanda sultana bağımlıdır, kariyer tamamen devlet atamasına tabidir. Öğrenci bu ikilemli yapıyı analiz etmeli, örneklerle desteklemelidir."
    },
    {
        soru: "<i>\"Osmanlı döneminde heterodoks dini akımlar, özellikle Anadolu'da güçlü bir varlık sürdürdü. Devletin bu akımlara yaklaşımı dönemden döneme değişti; bazen hoşgörülü, bazen baskıcı bir politika izlendi. Bu gerilim, resmi Osmanlı İslam anlayışıyla halk dindarlığı arasındaki derin farkı yansıtmaktadır.\"</i><br><br><b>Osmanlı dini kültür anlayışındaki çoğulculuk ve gerilim olgusunu metinden hareketle açıklayınız. Bu tablonun Osmanlı kültür ve eğitim politikalarına yansımalarını değerlendiriniz.</b>",
        cevap: "Doğru yanıt şunları içermelidir: Çoğulculuk: Osmanlı, Sünni İslam'ı resmi din olarak benimsemekle birlikte Alevi-Bektaşi, Mevlevi ve çeşitli heterodoks akımları Anadolu'da barındırıyordu. Bu çeşitlilik, hem kültürel zenginlik hem de yönetimsel bir zorluk oluşturuyordu. Gerilim: Devlet; Safevilerle mücadele, Kızılbaş isyanları ve şehir-köy arasındaki kültürel farklılıklar nedeniyle heterodoks akımlara tutarsız bir tutum sergiledi. Eğitim-kültür politikasına yansımaları: Medrese eğitiminin Sünni çerçevede kalması, resmi kültürün homojenleştirilmesini hedefliyordu. Ancak Mevleviler gibi tarikatlar kültürel üretimde (edebiyat, müzik, mimari) özerk bir alan koruyabildi. Öğrenci; Osmanlı kültürünün resmi ve gayri-resmi katmanlarını analiz etmeli, ikisinin arasındaki müzakereyi değerlendirmelidir."
    }
];

window.allTests["klasik_u3_bilim_2"] = [
    {
        soru: "<i>\"Osmanlı nesirinin gelişimi, özellikle 16. yüzyıldan itibaren, tarih yazımının çeşitlenmesiyle paralel seyretti. Vakayinameler, biyografik sözlükler (tezkireler) ve seyahatnameler, Osmanlı kültürel hayatının zenginleştiğine işaret eden edebi türlerdir. Bu eserlerin çoğu, doğrudan saray himayesinde kaleme alınmıştır.\"</i><br><br><b>Osmanlı edebiyatının farklı türlerini tarihsel kaynaklar olarak işlevleri açısından değerlendiriniz. Saray himayesinin edebi üretim üzerindeki olumlu ve olumsuz etkilerini tartışınız.</b>",
        cevap: "Doğru yanıt şunları kapsamalıdır: Edebi türlerin kaynak değeri: Vakayinameler siyasi olayları aktarırken tezkireler entelektüel ve sosyal tarihe ışık tutar; seyahatnameler coğrafi ve kültürel bilgiyi kayıt altına alır. Her tür farklı bir tarihsel perspektif sunar. Saray himayesinin olumlu etkileri: Maddi destek, sanatçının özgün eserler üretmesine olanak tanıdı. Saray kütüphaneleri ve nakkaşhaneler bilgi birikiminin korunmasını ve çoğaltılmasını sağladı. Olumsuz etkileri: Himayenin doğasında övgü ve propaganda unsurları vardır. Patronun yüceltilmesi için tarihsel gerçekler çarpıtılabilir, eleştirel perspektif zayıflayabilir. Öğrenci; Osmanlı edebi üretimini doğrudan bir tarihsel yansıma değil, bağlamı olan yorumlu kaynaklar olarak ele almalıdır."
    },
    {
        soru: "<i>\"Enderun mektebi, Osmanlı devlet yönetiminin en özgün kurumlarından biridir. Devşirme kökenli öğrenciler sarayda hem askerî hem de idari yönden yetiştirilirdi. Bu kurum, yetenekli bireylerin din ve etnik köken ayrımı gözetilmeksizin devlet kademelerine alınmasını sağlayan meritokratik bir yapıya sahipti.\"</i><br><br><b>Enderun mektebinin Osmanlı devlet yönetim anlayışındaki yerini analiz ediniz. Bu kurumun medreseyle karşılaştırıldığında farklı ne tür bir eğitim modeli oluşturduğunu açıklayınız.</b>",
        cevap: "Doğru yanıt şunları kapsamalıdır: Enderun'un konumu: Saray içindeki Enderun, devletin en üst kademelerine (veziriazam, kapıkulu askeri liderliği) taşıyıcı bir işlev gördü. Yönetim anlayışıyla ilişkisi: Devşirme sistemi üzerine kurulu Enderun; aileden ve yerel güç odaklarından bağımsız, sultana sadık bir yönetici sınıfı oluşturuyordu. Bu, merkezileşme politikasının eğitime yansımasıdır. Medreseyle karşılaştırma: Medrese dini ilimler, hukuk ve entelektüel birikimi esas alırken; Enderun askerlik, diplomasi, idari beceriler ve sanat (müzik, hat) gibi pratik devlet yönetimi becerilerine odaklanıyordu. Medrese ulemasını, Enderun devşirme bürokrasisini yetiştiriyordu; bu iki kanalın bir arada varlığı, Osmanlı yönetiminde ikili bir yapı oluşturuyordu. Öğrenci bu karşılaştırmayı somutlaştırmalıdır."
    },
    {
        soru: "<i>\"Osmanlı nakkaşhanesi, yüzyıllar boyunca sanatçıların bir atölye ortamında yetiştirilerek üretim yaptığı kurumsal bir yapıya sahipti. Özellikle Kanuni Sultan Süleyman döneminde Şahkulu ve Kara Memi gibi ustalar, İran ve Türkmen minyatür geleneklerini Osmanlı estetik anlayışıyla harmanlayarak özgün bir üslup oluşturdular.\"</i><br><br><b>Osmanlı nakkaşhanesinin kurumsal yapısı ile sanatsal üretim kalitesi arasındaki ilişkiyi açıklayınız. Kültürel sentez kavramını minyatür sanatı örneği üzerinden değerlendiriniz.</b>",
        cevap: "Doğru yanıt şunları içermelidir: Kurumsal yapı ve kalite ilişkisi: Nakkaşhane, saray bünyesinde çıraklıktan ustalığa uzanan kurumsallaşmış bir atölyeydi. Sürekli üretim ortamı ve ustadan öğrenciye aktarılan bilgi birikimi, teknik kaliteyi güvence altına alıyordu. Kültürel sentez: Osmanlı minyatürü, Safevi ve Türkmen boyama geleneklerini yalnızca taklit etmedi; bunlara yerel estetik değerler, saray töreni ve Osmanlı'ya özgü kentsel imgeler katarak yeni bir üslup yarattı. Bu sentez, alıcı kültürün seçici ve yaratıcı rolünü göstermektedir. Kara Memi örneği: Çiçek motifleri ve doğa temasını öne çıkaran Kara Memi üslubu, Osmanlı sanatında İran tesirini özümseyerek aşan bir örnek oluşturmaktadır. Öğrenci; sentezin basit bir taklit değil, özgün bir yaratıcılık biçimi olduğunu vurgulamalıdır."
    },
    {
        soru: "<i>\"Osmanlı tıp kurumlarının başında gelen darüşşifalar, modern hastane anlayışının İslam dünyasındaki öncülleriydi. Edirne Darüşşifası ve ardından gelen Süleymaniye Darüşşifası, hem hasta bakımı hem de tıp eğitimini bir arada sağlayan mekânlardı. Bu kurumların varlığı, Osmanlı yönetiminin sağlık ve bilim alanındaki kurumsal vizyonunu ortaya koymaktadır.\"</i><br><br><b>Osmanlı darüşşifalarının hem sağlık hizmeti hem de eğitim kurumu olarak çift işlevini analiz ediniz. Bu yapının Osmanlı bilim ve külliye anlayışına katkısını değerlendiriniz.</b>",
        cevap: "Doğru yanıt şunları kapsamalıdır: Çift işlev analizi: Darüşşifalar, hastane olarak tıbbi bakım sunarken aynı zamanda tıp eğitiminin pratikte verildiği mekânlardı. Bu yapı, öğrencinin teorik bilgisini hastalarla çalışarak pekiştirmesini sağlıyordu. Külliye bütünlüğü: Darüşşifa çoğunlukla külliyenin bir parçasıyydı; cami, medrese ve imareti tamamlıyordu. Bu bütünlük, Osmanlı devletinin sosyal sorumluluğunu ve kurumsal organizasyon kapasitesini sergiliyordu. Bilimsel katkı: Osmanlı darüşşifaları, İslam tıp mirasını (İbn Sina, Razi) uygulamalı öğretimle aktarıyordu. Aynı zamanda akıl hastalıklarının tedavisine özgü bölümler içermesi, Osmanlı tıbbının ileri bir boyutunu yansıtır. Öğrenci; bu kurumların yalnızca hayırseverlik değil, bilinçli bir bilim politikasının ürünü olduğunu argümanlaştırmalıdır."
    },
    {
        soru: "<i>\"17. yüzyıla gelindiğinde Osmanlı medreselerindeki eğitim kalitesi tartışmalı hâle geldi. Ulema sınıfının miras yoluyla genişlemesi, akademik liyakatin yerini aile bağlarının aldığı bir yapıya zemin hazırladı. Bu gelişme, Osmanlı entelektüel hayatındaki dönüşümün önemli bir boyutunu oluşturmaktadır.\"</i><br><br><b>17. yüzyılda Osmanlı medrese sisteminin nasıl bir dönüşüm geçirdiğini metinden hareketle açıklayınız. Bu dönüşümün Osmanlı bilim ve kültür hayatı üzerindeki etkilerini değerlendiriniz.</b>",
        cevap: "Doğru yanıt şunları içermelidir: Dönüşümün içeriği: Ulema sınıfının kendi içine kapanması ve görevlerin babadan oğula geçmesi, kuruluş dönemindeki meritokratik anlayıştan kopuşu simgeliyor. Liyakat yerine aile bağı belirleyici hale gelince medrese eğitiminin entelektüel seviyesi düştü. Bilim ve kültüre etkileri: Yenilikçi bilimsel çalışmaların azaldığı, üretimin nakilci bir çerçevede kaldığı görülmektedir. Bu, 17. yüzyıl Osmanlı düşüncesindeki dogmatikleşme eğiliminin medrese boyutudur. Karşılaştırmalı perspektif: Kuruluş ve yükseliş dönemlerinde medrese; devlet, bilim ve kültürün buluşma noktasıydı. 17. yüzyılda ise bu dinamik alanın sertleştiği, kapalı bir hiyerarşiye dönüştüğü görülmektedir. Öğrenci; bu değişimi yalnızca bireysel başarısızlık değil, kurumsal bir bozulma süreci olarak analiz etmelidir."
    },
    {
        soru: "<i>\"Osmanlı saray kültüründe şairler, sultan ve vezirlerin meclislerinde ayrıcalıklı bir konum elde edebiliyordu. Saray şiirinde somutlaşan bu ilişki, sanatın salt estetik değil, aynı zamanda güç ve patronaj ilişkilerinin de bir ürünü olduğunu göstermektedir. Şehnamecilik kurumu ise bu ilişkinin resmî ifadesiydi.\"</i><br><br><b>Osmanlı saray şiiri ile siyasi iktidar arasındaki ilişkiyi metinden hareketle tartışınız. Şehnamecilik kurumunun nasıl bir siyasi işlev üstlendiğini analiz ediniz.</b>",
        cevap: "Doğru yanıt şunları kapsamalıdır: Şiir-iktidar ilişkisi: Saray şiiri, patronun yüceltilmesini merkeze alıyordu. Kasideler ve övgü şiirleri, siyasi meşruiyet inşasının söylemsel araçlarıydı. Şairin maddi güvencesi patronun cömertliğine bağlıydı; bu durum edebi özgürlüğü kısıtlıyordu. Şehnamecilik kurumu: Şehnameciler, devletin resmi tarih yazıcılarıydı. Seferleri, zafer ve fetihleri kalıcı metinlere dönüştürerek sultana tarihsel bir imaj kazandırıyordu. Bu rol, Osmanlı'nın Arap ve Fars edebiyat geleneğini bilinçli olarak sahiplendiğini gösterir. Siyasi işlev: Şehnameci, askeri zaferleri kültürel miras haline dönüştüren bir 'tarihsel bellek yöneticisi' olarak çalışıyordu. Bu, devletin kültürü araçsallaştırmasının açık bir örneğidir. Öğrenci; sanat üretiminin bağımsızlık ve bağımlılık arasındaki gerilimi ele almalıdır."
    },
    {
        soru: "<i>\"Osmanlılar, Batı teknoloji ve bilimlerine karşı seçici bir tutum sergiledi. Özellikle askeri teknoloji ve haritacılık alanında Batı'dan etkilenmekten kaçınmadılar; ancak eğitim ve bilimsel kurumların köklü biçimde Batılılaştırılmasına 18. yüzyıla kadar mesafeli kaldılar. Bu tutum, Osmanlı entelektüel özgüveninin bir yansımasıydı.\"</i><br><br><b>Osmanlıların Batı bilimine karşı 'seçici alıcılık' tutumunu metinden hareketle analiz ediniz. Bu tutumun Osmanlı bilim kültürünün güçlü ve zayıf yönlerini nasıl yansıttığını değerlendiriniz.</b>",
        cevap: "Doğru yanıt şunları içermelidir: Seçici alıcılığın içeriği: Osmanlı, işlevsel ve askeri açıdan acil ihtiyaçlarını karşılayan teknolojileri (top dökmeciliği, haritacılık, tıbbi tedaviler) benimsedi; ancak bütüncül bir kurum reformuna yönelik talep 18. yüzyıla kadar belirgin değildi. Güçlü yanlar: Seçici alıcılık, Osmanlı kimliğinin korunmasını sağladı ve özgüven kaybı yaşanmadan teknik ilerlemeye olanak tanıdı. Zayıf yanlar: Kümülatif bir bilim geleneği oluşturmak yerine parçalı alımlama, Avrupa'daki bilimsel devrim ile arasındaki uçurun derinleşmesine katkıda bulundu. Entelektüel özgüven meselesi: Osmanlı, kendi bilim ve eğitim sisteminin yeterli olduğuna olan inancını uzun süre korudu. Bu özgüven bir noktaya kadar haklıyken; 17. yüzyıldan itibaren giderek bir körlüğe dönüştü. Öğrenci bu ikilemli tabloyu somut örneklerle açıklamalıdır."
    },
    {
        soru: "<i>Kaynak 1: \"Sinan'ın eserleri, yalnızca teknik ustalığın değil, aynı zamanda imparatorluk ideolojisinin de somutlaşmasıdır. Selimiye'nin dört minaresi ve merkezi kubbesi, Osmanlı sultanını meşruiyet simgesi olarak mimari diline çevirmektedir.\"<br><br>Kaynak 2: \"Osmanlı mimarisinde görsel propaganda unsurları, erken dönemden itibaren bilinçli olarak kullanılmıştır. Bursa'dan İstanbul'a taşınan mimari anlayış, kubbe ve minarenin siyasi sembolizmini giderek pekiştirdi.\"</i><br><br><b>Bu iki metni karşılaştırarak Osmanlı mimarisinin kuruluştan zirveye uzanan süreçte siyasi bir söylem aracına nasıl dönüştüğünü analiz ediniz. Farklı dönemlerden iki mimari örnek seçerek argümanınızı somutlaştırınız.</b>",
        cevap: "Doğru yanıt şunları kapsamalıdır: İki metnin karşılaştırması: Artan, mimari sembolizmin erken dönemden itibaren var olduğuna dikkat çekerken; Necipoğlu, Sinan dönemiyle birlikte bu sembolizmin sistemli ve kuramsal bir boyut kazandığını vurgular. İki metin birlikte, Osmanlı mimarisinde siyasi söylemin kuruluştan zirveye evrilen bir derinleşme süreci geçirdiğini ortaya koyar. Siyasi dönüşüm analizi: Erken dönemde (Bursa, Yeşil Camii): Selçuklu ve Bizans unsurlarının sentezi, yeni devletin meşruiyetini inşa etmeye yönelik bir mimari dil oluştururken; Klasik dönemde (Selimiye, Süleymaniye): Külliye kompleksi ve anıtsal kubbe mimarisi, imparatorluk gücünün mutlakiyet iddiasını görsel olarak ilan etti. Mimari örnekler: Bursa Yeşil Türbe (kuruluş): Osmanlı kimliğinin biçimlenme süreci; Edirne Selimiye (zirve): Mimari aracılığıyla evrensel Osmanlı meşruiyetinin ilanı. Öğrenci; sembolizmin tarihsel derinleşmesini somut örneklerle açıklamalı ve iki kaynağı kendi içinde eleştirel biçimde değerlendirmelidir."
    },
    {
        soru: "<i>Kaynak 1: \"Osmanlı bilim anlayışı, İslam ilim geleneğini devam ettirmekle birlikte klasik İslam düşüncesinin pratik uygulamalarına olan ilgisiyle öne çıktı. Tıp, matematik ve astronomi gibi alanlarda Osmanlı alimleri hem derleyici hem de yenilikçi bir rol üstlendi.\"<br><br>Kaynak 2: \"17. yüzyılda Evliya Çelebi gibi Osmanlı gezginlerinin coğrafi gözlemleri, Osmanlı bilgisinin empirik bir boyut kazanmakta olduğunu göstermektedir. Bu gelişme, klasik İslam bilim geleneğiyle modern bilimsel pratik arasındaki köprüyü somutlaştırmaktadır.\"</i><br><br><b>Her iki metni birlikte değerlendirerek 16. ve 17. yüzyıl Osmanlı bilim anlayışının devamlılık ve dönüşüm açısından nasıl ele alınabileceğini tartışınız. Osmanlı'nın bilimsel gelişiminin Avrupa'daki bilimsel devrimle hangi noktalarda kesiştiğini veya ayrıştığını analiz ediniz.</b>",
        cevap: "Doğru yanıt şunları içermelidir: Devamlılık: İhsanoğlu'nun vurguladığı üzere Osmanlı bilimi İslam mirasını derleyerek aktarmayı sürdürdü. Bu derleyicilik, bilginin korunması açısından değerliydi. Dönüşüm: Hagen'in işaret ettiği empirik gözlem boyutu, 17. yüzyılda yeni bir bilme biçiminin filizlendiğini göstermektedir. Evliya Çelebi'nin ayrıntılı coğrafi ve etnografik gözlemleri salt normatif bilginin ötesine geçer. Avrupa ile karşılaştırma: Kesişim: Her iki tarafta da pratik bilgiye ilgi, gözlem ve deney vurgusu artmaktadır. Ayrışma: Avrupa'da kurumsal bir 'bilimler cumhuriyeti' (republic of letters) oluşurken; Osmanlı'da bilimsel üretim hâlâ saray ve medrese gibi bağımsızlıktan yoksun kurumsal yapılara sıkıştı. Ayrıca matbaanın gecikmeli benimsenmesi bilginin yaygınlaşmasını yavaşlattı. Öğrenci; iki metni birlikte kullanarak Osmanlı bilimini hem kendi iç dinamikleri hem de küresel bağlamda değerlendirmelidir."
    },
    {
        soru: "<i>Kaynak 1: \"Fatih Sultan Mehmed'in politikası, yalnızca askeri fethi değil aynı zamanda kültürel bir yeniden yapılanmayı da kapsamaktaydı. İstanbul'un imarı, Bizans'tan devralınan yapıların dönüştürülmesi ve yeni külliye inşaatları, Osmanlı medeniyetinin inşasında sembolik bir anlam taşıyordu.\"<br><br>Kaynak 2: \"17. yüzyıl Osmanlı kültür ortamında sultanın kişisel katkısı azalmakta, bürokrasinin ve ulemanın kültürel üretim üzerindeki belirleyiciliği artmaktaydı. Bu dönüşüm, sanat ve bilim patronajının doğasında da köklü bir değişimi beraberinde getirdi.\"</i><br><br><b>Bu iki metni karşılaştırarak Osmanlı kültür patronajının 15. yüzyıldaki niteliğini 17. yüzyıldaki biçimiyle karşılaştırınız. Bu değişimin Osmanlı bilim, eğitim ve sanat alanlarındaki somut yansımalarını tartışınız.</b>",
        cevap: "Doğru yanıt şunları kapsamalıdır: 15. yüzyıl patronajı (İnalcık metni): Fatih döneminde patronaj, doğrudan sultanın kişisel ilgi ve iradesiyle şekilleniyordu. Sultan; bilgin davet ediyor, külliye inşa ettiriyor, bilim ve kültür üretiminin bizzat sürücüsü oluyordu. Bu, merkezi ve kişisel bir patronaj modelidir. 17. yüzyıl dönüşümü (Abou-El-Haj metni): Sultanın kültürel liderlik rolü zayıflarken bürokrasi ve ulema belirleyici hale geldi. Bu dönüşüm; sanat ve bilim üretimini daha kurumsal ama aynı zamanda daha muhafazakar bir zemine taşıdı. Somut yansımalar: Bilim: Rasathanenin yıkılması (1580) sultan iradesinin yerini ulema baskısına bırakmasının erken bir örneğidir. Eğitim: Medrese dejenere olarak liyakat yerine soyağacı patronajına evrildi. Sanat: Nakkaşhane üretimi 17. yüzyılda tekrarlayıcı bir çizgiye girerken, erken dönemde risk alan özgün eserlerin azaldığı görülür. Öğrenci; patronaj değişimini kurumsal ve kişisel boyutlarıyla değerlendirmeli, somut örneklerle argümanını güçlendirmelidir."
    }
];
window.allTests = window.allTests || {};

window.allTests["klasik_u3_bilim_3"] = [
    {
        soru: "<i>\"Fatih Sultan Mehmed, İstanbul'u fethettikten sonra kütüphane kurmayı bizzat himaye etti; Doğu ve Batı dillerindeki el yazmalarını toplatarak saray kütüphanesinin temelini attı. Bu girişim, sultanın kültürel mirasa olan ilgisinin yanı sıra İstanbul'u entelektüel bir merkeze dönüştürme hedefini de yansıtıyordu.\"</i><br><br><b>Metinden hareketle Fatih Sultan Mehmed'in kütüphane politikasını ve bu politikanın Osmanlı kültür anlayışındaki yerini açıklayınız.</b>",
        cevap: "Doğru yanıt şunları içermelidir: Kütüphane politikası: Fatih, fetihten hemen sonra bilgi birikimini derleme faaliyetine girişti. Farklı dillerdeki el yazmalarını saray kütüphanesinde bir araya getirmek, Osmanlı'nın yalnızca İslam dünyasının değil, evrensel medeniyetin mirasçısı olduğu iddiasını somutlaştırıyordu. Kültürel anlayıştaki yeri: Bu girişim, Osmanlı'nın 'gazi devlet' kimliğinin ötesinde 'medeniyet devleti' inşa etme çabasını temsil eder. Bilgiyi korumak, toplamak ve yeniden üretmek bir iktidar stratejisiydi. Öğrenci; kütüphanenin salt enformasyon deposu değil, kültürel egemenliğin sembolik bir aracı olduğunu analiz etmelidir."
    },
    {
        soru: "<i>\"Osmanlı sarayında müzik, eğlence olmanın çok ötesinde bir anlam taşıyordu. Sultanın meclisinde icra edilen musiki; savaş zaferlerini kutlamaktan dini törenlere, yabancı elçi kabullerinden gündelik saray ritüellerine kadar geniş bir işlevler dizisine sahipti. Osmanlı müzisyenleri arasında farklı etnik kökenlerden isimler yer alıyordu.\"</i><br><br><b>Metne göre Osmanlı saray müziğinin işlevsel çeşitliliğini açıklayınız. Müziğin saray kültüründeki bu çok yönlü varlığının Osmanlı toplumsal ve siyasi yaşamına katkısını değerlendiriniz.</b>",
        cevap: "Doğru yanıt şunları içermelidir: İşlevsel çeşitlilik: Osmanlı saray müziği; törensel (hükümdar kabulü, zafer kutlaması), dini (Mevlid, Ramazan törenleri) ve gündelik (mehter, eğlence meclisi) işlevleri bir arada yerine getiriyordu. Müzik, ritim ve ses aracılığıyla toplumsal düzeni ve siyasi hiyerarşiyi de pekiştiriyordu. Siyasi ve toplumsal katkı: Mehter müziği, ordunun ve devletin gücünü sembolik olarak ilan ederken; saray meclisindeki müzik, sultanın otoritesinin kültürel boyutunu temsil ediyordu. Çok etnikli yapı: Ermeni, Rum, Yahudi ve Müslüman müzisyenlerin bir arada yer alması, Osmanlı kültürünün ne ölçüde çoğulcu bir zemine oturduğunu göstermektedir. Öğrenci; müziği siyasi temsil ve toplumsal birliktelik aracı olarak analiz etmelidir."
    },
    {
        soru: "<i>\"Osmanlı Türkçesinin edebiyat dili olarak olgunlaşması, yalnızca dilbilimsel bir gelişme değil, aynı zamanda siyasi bir tercihti. Arapça ve Farsça ile eşdeğer bir prestij kazanmaya çalışan Osmanlı Türkçesi, özellikle 15. yüzyıldan itibaren hem sarayda hem halk çevrelerinde ürün vermeye başladı.\"</i><br><br><b>Osmanlı Türkçesinin edebiyat dili olarak gelişimini metinden hareketle açıklayınız. Dilin bu dönüşümünün Osmanlı kültürel kimliğinin oluşumundaki rolünü değerlendiriniz.</b>",
        cevap: "Doğru yanıt şunları içermelidir: Dilin gelişimi: 15. yüzyıla kadar Arapça ve Farsça ilim ve edebiyat dili olarak ön plandaydı. Osmanlı Türkçesi, bu dönemden itibaren özellikle saray himayesiyle edebiyat dili kimliği kazandı. Bu süreç, dilin sadeleşmesi ve söz varlığının zenginleşmesiyle birlikte ilerledi. Siyasi tercih boyutu: Bir dilin kültür dili olarak seçilmesi, hanedanın ve devletin kimliğini şekillendirir. Osmanlı, İslam dünyasının geleneksel dilleriyle rekabete girerken kendi dilini de güçlendirmeyi hedefledi. Kültürel kimlik: Osmanlı Türkçesinin gelişimi, kuruluş döneminin göçebe ve heterojen yapısından klasik bir imparatorluk kültürüne geçişin dilsel boyutunu oluşturmaktadır. Öğrenci; dil politikasını kimlik inşasının bir aracı olarak analiz etmelidir."
    },
    {
        soru: "<i>\"Fatih Sultan Mehmed tarafından İstanbul'da kurulan Sahn-ı Seman medreseleri, Osmanlı eğitim hiyerarşisinin zirvesini oluşturuyordu. Sekiz medreseden oluşan bu kompleks, sadece dini ilimler değil; matematik, felsefe ve tıp gibi aklî ilimlere de yer veriyordu. Bu çeşitlilik, Osmanlı yükseköğretiminin ne ölçüde kapsamlı bir bilgi anlayışını benimsediğini ortaya koymaktadır.\"</i><br><br><b>Sahn-ı Seman medreselerinin Osmanlı eğitim anlayışındaki yeri ve önemini metinden hareketle analiz ediniz. Bu kurumun 'aklî ilimler' ile 'naklî ilimler' arasındaki dengeyi nasıl kurduğunu değerlendiriniz.</b>",
        cevap: "Doğru yanıt şunları içermelidir: Sahn-ı Seman'ın konumu: Fatih'in İstanbul'da kurduğu sekiz medreseden oluşan bu kompleks, hem coğrafi hem de eğitim hiyerarşisi açısından Osmanlı yükseköğretiminin merkeziydi. Müfredat çeşitliliği: Aklî ilimler (matematik, felsefe, doğa bilimleri) ile naklî ilimler (tefsir, hadis, fıkıh) birlikte öğretiliyordu. Bu entegre yaklaşım, Osmanlı'nın bilgiyi parçalara bölmeyen bütüncül bir anlayışa sahip olduğunu gösterir. Tarihsel değerlendirme: Sahn-ı Seman, Osmanlı'nın hem dini-hukuki hem de entelektüel bir liderlik iddiasını kurumsal olarak temellendirdiği mekândı. Öğrenci; bu yapının yalnızca eğitim değil, meşruiyet üretme işlevi de gördüğünü analiz etmelidir."
    },
    {
        soru: "<i>\"Osmanlı şiirinde Fuzuli, Baki ve Hayali gibi büyük şairlerin divan geleneğine katkıları, yalnızca estetik değer açısından değil, toplumsal söylem açısından da son derece önemlidir. Bu şairler, aşk ve güzellik temalarının ardına saklanmış felsefi sorgulamaları ve toplumsal eleştirileri şiirlerine yedirdiler.\"</i><br><br><b>Osmanlı divan şiirinin görünür temaları (aşk, güzellik) ile örtük anlamları (felsefi sorgulama, toplumsal eleştiri) arasındaki ilişkiyi değerlendiriniz. Bu özelliklerin Osmanlı kültür ortamının hangi niteliklerini yansıttığını açıklayınız.</b>",
        cevap: "Doğru yanıt şunları içermelidir: Görünür ve örtük anlamlar: Divan şiirinin aşk ve güzellik temaları, Osmanlı toplumunda ortak bir estetik dil oluşturuyordu. Ancak bu yüzeyin altında metafizik sorular (Tanrı-insan ilişkisi, varoluşun anlamı) ve toplumsal eleştiriler (riya, iktidar ilişkileri) yer alıyordu. Bu katmanlı yapı, şaire doğrudan söylenemeyeni örtülü biçimde ifade etme imkânı tanıyordu. Kültür ortamının nitelikleri: Osmanlı entelektüel ortamında doğrudan eleştiri tehlikeliydi; dolayısıyla şiir, denetimden görece bağımsız bir düşünce alanı işlevi gördü. Tasavvuf etkisi de şiirin bu çok katmanlı yapısını besleyen önemli bir unsurdur. Öğrenci; divan şiirini sansür ve örtük iletişim bağlamında da analiz etmeli, edebiyatın toplumsal işlevini derinlemesine irgelemelidir."
    },
    {
        soru: "<i>\"Piri Reis'in 1513 tarihli dünya haritası, Osmanlı coğrafya bilgisinin ne denli kapsamlı bir birikimi temsil ettiğinin somut kanıtıdır. Bu harita, Portekiz keşif seferlerinden elde edilen verileri İslam kartografya geleneğiyle harmanlayarak özgün bir coğrafi belge ortaya koymuştur.\"</i><br><br><b>Piri Reis haritasını bir bilimsel ürün olarak analiz ediniz. Bu eserin Osmanlı coğrafya ve bilim anlayışının hangi özelliklerini yansıttığını tartışınız.</b>",
        cevap: "Doğru yanıt şunları kapsamalıdır: Bilimsel ürün olarak Piri Reis haritası: Harita, Portekiz deniz kâşiflerinin verilerini, Christopher Columbus'un günlüklerini ve İslam kartografya geleneğini sentezlemektedir. Bu entegrasyon, Osmanlı'nın dönemin küresel bilgi ağlarına entegre olduğunu göstermektedir. Osmanlı coğrafya anlayışının yansıması: Osmanlı coğrafyacıları yalnızca kendi topraklarını değil, dünyanın tamamını haritalamayı hedefliyordu. Bu evrensel bakış açısı, Osmanlı'nın kendini evrensel bir imparatorluk olarak konumlandırmasıyla örtüşmektedir. Seçici alıcılık: Batı'nın keşif verilerini İslam coğrafya bilgisiyle harmanlamak, Osmanlı'nın Batı bilgisini reddeden değil sentezleyen bir tutum sergilediğini kanıtlar. Öğrenci; bu haritayı hem bilimsel hem de siyasi/ideolojik bir metin olarak okumalıdır."
    },
    {
        soru: "<i>\"Mevlevi tarikatı, Osmanlı döneminde yalnızca bir tasavvuf geleneği olmanın ötesinde sanat ve kültürün de taşıyıcısı oldu. Konya merkezi etrafında gelişen Mevlevihane ağı, şiir, müzik ve sema gibi pratikler aracılığıyla hem saray hem halk çevrelerinde derin bir kültürel etki bıraktı.\"</i><br><br><b>Mevlevi tarikatının Osmanlı kültürel ve sanatsal yaşamındaki rolünü değerlendiriniz. Dini bir kurumun kültür üretimindeki bu etkinliğinin Osmanlı devlet-toplum ilişkisi açısından ne anlama geldiğini açıklayınız.</b>",
        cevap: "Doğru yanıt şunları içermelidir: Mevlevilerin kültürel rolü: Mevlevilik; şiir (Mevlana geleneği, divan edebiyatıyla bütünleşme), müzik (ney, kudüm) ve dans (sema) gibi sanatsal pratiklerle Osmanlı kültürel yaşamının merkezinde yer aldı. Mevlevihane ağı, başkent dışında taşraya uzanan bir kültürel altyapı oluşturdu. Devlet-toplum ilişkisi boyutu: Osmanlı devleti, Mevlevilere genel olarak hoşgörüyle yaklaştı. Bu ilişki; devletin heterodoks unsurlara yaklaşımındaki pragmatizmi, kültürel çoğulculuğu ve tarikatların devlet meşruiyetine katkı sağlayabileceği anlayışını yansıtmaktadır. Öğrenci; tarikatların resmi Osmanlı İslam anlayışıyla ilişkisini, kültürel özerklik kavramını ve taşraya kültür taşımadaki işlevini analiz etmelidir."
    },
    {
        soru: "<i>\"Topkapı Sarayı'nda bulunan mimari çizim rulolarından anlaşıldığı üzere Osmanlı mimarları, geometrik tasarım ilkelerini hem teorik hem pratik düzeyde özümsemiş profesyonellerdi. Bu belgeler, sözlü aktarım ötesinde yazılı ve görsel bir mimari bilgi geleneğinin varlığını kanıtlamaktadır.\"</i><br><br><b>Osmanlı mimarlarının mesleki bilgi birikimini ve bu bilginin kuşaklar arası aktarım biçimini metinden hareketle analiz ediniz. Bu durumu Osmanlı bilim ve eğitim anlayışının genel çerçevesiyle nasıl ilişkilendirirsiniz?</b>",
        cevap: "Doğru yanıt şunları kapsamalıdır: Mesleki bilgi birikimi: Topkapı rulolarının varlığı, Osmanlı mimarlarının yalnızca usta-çırak sözlü aktarıma değil, yazılı ve görsel belgelere de dayandığını göstermektedir. Geometrik ilkelerin teorik kavranışı, mimarların salt teknisyen değil, matematiksel düşünce sistemi olan entelektüeller olduğunu ortaya koyar. Kuşaklar arası aktarım: Nakkaşhane ve saray atölyeleriyle paralel biçimde, mimarlıkta da kurumsal bir bilgi aktarım mekanizması gelişmişti. Genel eğitim anlayışıyla ilişki: Osmanlı'da teorik ve pratik bilginin iç içe geçmesi hem medreste hem de zanaat geleneğinde kendini göstermektedir. Öğrenci; Osmanlı bilgisinin yalnızca dini-edebi değil, uygulamalı ve teknik bir boyutu olduğunu vurgulamalıdır."
    },
    {
        soru: "<i>\"Kanuni Sultan Süleyman dönemi, Osmanlı'nın yalnızca askeri değil kültürel açıdan da zirvesini temsil etmektedir. İbrahim Paşa gibi vezirlerin sanat ve edebiyat patronajı; şairlerin, mimarların ve müzisyenlerin bir arada bulunduğu dinamik bir entelektüel çevre oluşturdu.\"</i><br><br><b>İbrahim Paşa'nın sanat ve edebiyat patronajını Osmanlı kültürel yaşamındaki önemi açısından değerlendiriniz. Bir veziirin bu rolü üstlenmesinin siyasi ve kültürel anlamını tartışınız.</b>",
        cevap: "Doğru yanıt şunları kapsamalıdır: İbrahim Paşa patronajı: Sadece sultanın değil, veziriazamın da kültür patronu olması, Osmanlı'da kültürel destekçiliğin geniş bir sosyal tabana yayıldığını gösterir. İbrahim Paşa; şairleri, mimarları ve müzisyenleri bir araya getirerek sarayı gerçek anlamda bir kültür merkezi haline getirdi. Siyasi anlam: Bir veziirin sanata destek vermesi, onun meşruiyetini ve toplumsal statüsünü güçlendiriyordu. Kültürel patronaj, siyasi nüfuzu hem simgeleyen hem de artıran bir araçtı. Bu aynı zamanda sultanla veziir arasında kültürel alanda da bir güç dengesi yaratıyordu. Kültürel anlam: Vezirin patronajı; üretim merkezinin saraydan geniş bir yönetici kesime yayılmasını sağladı, böylece Osmanlı kültür ortamı çoğulculuk kazandı. Öğrenci; patronaj ilişkisini yalnızca estetik değil, iktidar ekonomisi çerçevesinde ele almalıdır."
    },
    {
        soru: "<i>\"17. yüzyıl Osmanlı toplumunda 'kalemiye' sınıfının yükselişi, bürokrasinin kültürel yaşam üzerindeki etkisini dönüştürdü. Yazışmalar, arşivler ve devlet yazışma geleneği, yeni bir aydın profili doğurdu; bu profil hem divan edebiyatına yakındı hem de pratik devlet işleriyle iç içeydi.\"</i><br><br><b>Osmanlı 'kalemiye' sınıfının ortaya çıkışını ve bu sınıfın kültürel-entelektüel yaşama katkısını metinden hareketle analiz ediniz. Bu gelişmenin 'ilmiye' (ulema) sınıfıyla ilişkisini değerlendiriniz.</b>",
        cevap: "Doğru yanıt şunları içermelidir: Kalemiye'nin yükselişi: 17. yüzyılda artan devlet bürokrasisinin yazışma, kayıt ve arşiv ihtiyacı, okur-yazar ve edebiyata vakıf bir bürokrat profili doğurdu. Bu kesim; hem devlet içindeydi hem de entelektüel bir kimlik taşıyordu. Kültürel-entelektüel katkı: Kalemiye mensupları; tarih yazımı, edebiyat ve eleştirel düşüncede özgün sesler olarak öne çıktı. Kâtip Çelebi ve Koçi Bey gibi figürler, bu sınıfın simgesidir. İlmiye ile karşılaştırma: İlmiye (ulema) dini otoritesini ve medrese ağını elinde bulundururken; kalemiye dünyevi devlet yönetiminin bilgi üreticisine dönüştü. İki sınıf arasındaki gerilim, 17. yüzyıl Osmanlı entelektüel yaşamının dinamiklerinden birini oluşturuyordu. Öğrenci; bu iki sınıfın Osmanlı bilgi ve kültür üretimini nasıl şekillendirdiğini analiz etmelidir."
    },
    {
        soru: "<i>\"Mimar Sinan'ın hayatı, Osmanlı toplumsal hareketliliğinin sınırlarını ve olanaklarını gözler önüne serer. Devşirme kökenli olan Sinan, Yeniçeri sınıfından başladığı kariyerini Hassa Baş Mimarı makamına taşıdı. Bu yükseliş, Osmanlı devlet yapısının yetenekli bireyleri öne çıkarma kapasitesini kanıtlamaktadır.\"</i><br><br><b>Mimar Sinan'ın kariyer yolculuğunu Osmanlı toplumsal hareketliliği ve devşirme sistemi açısından değerlendiriniz. Bu örneğin Osmanlı eğitim ve yetenek yönetimi anlayışına ilişkin ne söylediğini analiz ediniz.</b>",
        cevap: "Doğru yanıt şunları içermelidir: Kariyer yolculuğu: Sinan'ın Yeniçeri kökeninden Hassa Baş Mimarı'na uzanan yolu, Osmanlı sisteminin etnik ve sosyal kökenden bağımsız olarak yeteneği görüp değerlendirebildiğini gösterir. Devşirme sistemiyle ilişkisi: Devşirme, hem eğitim hem de kariyer kanalları sunuyordu. Enderun yalnızca siyasi-idari değil, sanatsal yetenekleri de besleyebilecek bir çevre sağlıyordu. Eğitim ve yetenek yönetimi: Osmanlı, bireyin potansiyelini devlet hizmetine yönlendiren kurumsal bir çerçeve geliştirdi. Bu çerçeve modern meritokrasi kavramıyla tam örtüşmese de döneminin koşullarında dikkat çekici bir açıklık sergiliyordu. Öğrenci; bu örneği Osmanlı toplumsal yapısındaki hareketlilik ile kısıtların karmaşık dengesi üzerinden analiz etmelidir."
    },
    {
        soru: "<i>\"Osmanlı'nın matbaayı kabul etmekteki gecikmesi, çoğu zaman basitçe 'kapalılık' ya da 'gerilik' biçiminde yorumlanmıştır. Oysa bu gecikme, hat ustaları ve ulema loncasının çıkarları, el yazması kitap ekonomisinin canlılığı ve bilginin yayılmasına ilişkin dini kaygılar gibi çok katmanlı etkenlerle açıklanmalıdır.\"</i><br><br><b>Osmanlı'nın matbaayı benimsemekteki gecikmesini salt bir 'gerilik' ya da 'kapalılık' olarak değerlendirmeyi eleştiren bu yaklaşımı tartışınız. Matbaa gecikmesinin Osmanlı bilim ve kültür ortamına olan etkilerini değerlendiriniz.</b>",
        cevap: "Doğru yanıt şunları içermelidir: Çok katmanlı açıklama: Matbaanın gecikmesi; hattatlar ve el yazması üreticilerinin ekonomik çıkarları (iş kaybı korkusu), ulemanın kutsal metnin baskı yoluyla çoğaltılmasına ilişkin dini kaygıları ve Arap harflerinin mekanik baskıya uyarlanmasındaki teknik güçlükler gibi birbiriyle örtüşen etkenlerden kaynaklandı. 'Gerilik' yorumuna eleştiri: Matbaa gecikmesi doğrusal bir ilerleme modeline dayanan Avrupamerkezci perspektiften 'gerilik' görünse de Osmanlı toplumunun kendi iç mantığı içinde rasyonel aktörlerin bilinçli tercihlerinin ürünüdür. Bu yaklaşım, Osmanlı'nın tarihsel süreçlerini kendi bağlamında değerlendirme gereğini hatırlatır. Bilim ve kültüre etkisi: Matbaanın gecikmeli benimsenmesi, bilginin geniş kitlelere yayılmasını yavaşlattı ve Avrupa'daki entelektüel hareketlilikle aradaki uçurun açılmasına katkıda bulundu. Öğrenci; gecikmeden 'kim yararlandı?' sorusunu da sorgulamalıdır."
    },
    {
        soru: "<i>\"Osmanlı medreselerinde kuruluş döneminin müfredatı, Sahn-ı Seman ile birlikte sistematik bir hale geldi. Fatih'in çıkardığı kanunname, hangi medresenin hangi dersi vereceğini, müderrislerin maaşlarını ve öğrencilerin sayısını belirliyor; böylece eğitim için ilk kapsamlı devlet düzenlemesi ortaya konuyordu.\"</i><br><br><b>Fatih Sultan Mehmed döneminde çıkarılan medrese kanunnamelerinin Osmanlı eğitim sistemine katkısını değerlendiriniz. Devletin eğitimi bu ölçüde düzenlemesinin sonuçlarını hem olumlu hem eleştirel açıdan tartışınız.</b>",
        cevap: "Doğru yanıt şunları içermelidir: Kanunnamelerin katkısı: Medrese kanunnameleri; eğitimin standartlaşmasını, kurumlar arası hiyerarşinin net belirlenmesini ve mali güvencenin kurumsal zemine oturtulmasını sağladı. Bu, eğitim kalitesinin sürekliliği açısından önemli bir adımdı. Olumlu sonuçlar: Standartlaşma; benzer eğitim kalitesinin farklı coğrafyalarda uygulanmasına zemin hazırladı, medrese mezunlarının ortak bir mesleki dil ve anlayış geliştirmesini kolaylaştırdı. Eleştirel değerlendirme: Devlet kontrolü, eğitimi merkezileştirdi; bu da zamanla müfredatın katılaşmasına ve yenilikçi bilimsel yaklaşımların önünün kapanmasına yol açtı. Kuralların belirlediği bir eğitim sistemi, aynı zamanda sorgulayıcı ve eleştirel bir zihnin gelişimini frenleyebilir. Öğrenci; standartlaşmanın 'kalitenin güvencesi mi, özgürlüğün kısıtı mı?' sorusunu birden fazla perspektiften değerlendirmelidir."
    },
    {
        soru: "<i>\"Osmanlı ordu teşkilatındaki teknik bilgi birikimi, yalnızca askeri tarihçilerin değil, bilim ve teknoloji tarihçilerinin de ilgi alanındadır. Top dökümü, balistik hesaplamalar ve istihkâm mimarisi gibi alanlarda Osmanlı'nın önemli teknik başarılar elde ettiği görülmektedir. Bu başarılar, Osmanlı'da bilim ile devlet pratiğinin ne denli iç içe geçtiğini kanıtlar.\"</i><br><br><b>Askeri teknoloji alanındaki Osmanlı bilgi birikimini, 'bilim ve devlet' ilişkisi bağlamında değerlendiriniz. Osmanlı'da hangi bilim alanlarının devlet pratiğiyle doğrudan ilişkilendirildiğini ve bunun bilimsel gelişim üzerindeki etkilerini tartışınız.</b>",
        cevap: "Doğru yanıt şunları içermelidir: Askeri teknoloji ve bilim: Osmanlı top dökümü; metalürji, mühendislik ve matematiksel hesaplama bilgisini gerektiriyordu. Bu durum, Osmanlı'da uygulamalı bilimin devlet ihtiyaçlarından beslendiğini göstermektedir. Bilim-devlet ilişkisi: Osmanlı bilimsel yatırımı büyük ölçüde pratik devlet ihtiyaçlarına yöneliktir: savaş teknolojisi, tıp, inşaat ve coğrafya öne çıkan alanlardır. Soyut bilimsel araştırma bu koşullarda ikinci planda kaldı. Etkiler: Olumlu: Pratik ihtiyaçların bilimi beslemesi, hızlı teknik gelişme sağladı. Olumsuz: Salt devlet faydasına odaklanma, teorik bilimin ve bağımsız araştırmanın gelişimini kısıtladı. Avrupa'nın bilimsel devrimiyle karşılaştırıldığında kurumsallaşmış teorik araştırma eksikliği önemli bir kırılma noktası oluşturuyordu. Öğrenci; uygulamalı bilim ile saf bilim arasındaki gerilimi tartışmalıdır."
    },
    {
        soru: "<i>\"Osmanlı saray kadınlarının kültürel patronajı, özellikle 16. yüzyıl ortasından itibaren belirginleşti. Hürrem Sultan, Mihrimah Sultan ve daha sonraki valide sultanlar; cami, medrese ve imaret yaptırarak kendi isimleriyle anılan külliyeler kurdu. Bu girişimler, saray kadınlarının siyasi meşruiyet arayışında mimari kültürü nasıl araçsallaştırdığını ortaya koymaktadır.\"</i><br><br><b>Osmanlı saray kadınlarının kültür patronajını ve mimari eserlerini, siyasi meşruiyet inşası bağlamında analiz ediniz. Bu örnekler, Osmanlı kültür ve sanat anlayışında kimin aktör olduğuna ilişkin nasıl bir tablo çizmektedir?</b>",
        cevap: "Doğru yanıt şunları içermelidir: Kadın patronajı ve meşruiyet: Hürrem Sultan ve Mihrimah Sultan gibi isimler; cami ve külliye inşa ettirerek sultanın yanı sıra 'himaye eden kadın' olarak tarihsel belleğe geçti. Mimari; hanedanın kadın üyelerine siyasi bir görünürlük ve kalıcılık sağlıyordu. Mimariyi araçsallaştırma: Külliye inşa etmek, 'halkın iyiliği için çalışan' bir figür olduğunu toplumsal olarak kanıtlamanın en etkili yoluydu. Bu yolla saray kadınları; din, hayırseverlik ve devlet arasındaki üçgeni kendi lehlerine kullandı. Kültürel aktörler sorusu: Bu örnekler; Osmanlı kültür üretiminin yalnızca sultanlar ve erkek bürokrasiyle sınırlı olmadığını, hanedan kadınlarının da bağımsız kültürel aktörler olarak sahneye çıkabildiğini göstermektedir. Öğrenci; cinsiyet, iktidar ve kültür ilişkisini bu özel bağlamda eleştirel biçimde analiz etmelidir."
    }
];
window.allTests = window.allTests || {};

window.allTests["test_u3_bilim_1"] = [
    {
        soru: "<i>\"Osmanlı medresesi, yalnızca din ilimleri öğreten bir kurum değildi; matematik, astronomi, mantık ve felsefe de müfredatın ayrılmaz parçalarıydı. Fâtih döneminde kurulan Sahn-ı Semân medreseleri, müfredatı ve fiziksel büyüklüğü bakımından dönemin İslam dünyasındaki en kapsamlı eğitim komplekslerinden birini oluşturuyordu.\"</i><br><br><b>İnalcık'ın bu değerlendirmesine göre Fâtih dönemi medreselerinin eğitim anlayışını en iyi tanımlayan ifade hangisidir?</b>",
        secenekler: [
            "A) Yalnızca Kur'an ve hadis merkezli bir müfredata sahip olan dinî kurumlardı.",
            "B) Din ilimleriyle birlikte akli bilimleri de kapsayan bütüncül bir eğitim programı sunan kurumlardı.",
            "C) Batı üniversite modelini örnek alarak laik müfredat uygulayan kurumlardı.",
            "D) Yalnızca devlet memuru yetiştirmeye odaklanan bürokratik eğitim merkezleriydi.",
            "E) Saray'ın doğrudan denetiminde olmayan bağımsız vakıf okullarıydı."
        ],
        cevap: "B) Din ilimleriyle birlikte akli bilimleri de kapsayan bütüncül bir eğitim programı sunan kurumlardı.",
        aciklama: "Metin, Osmanlı medresesinin matematik, astronomi, mantık ve felsefe gibi aklî bilimleri de kapsadığını açıkça vurgulamaktadır."
    },
    {
        soru: "<i>\"Sinan'ın yapıtları, mimarlığı salt teknik bir zanaat olmaktan çıkararak siyasi meşruiyetin ve imparatorluk ihtişamının görsel dili hâline getirdi. Süleymaniye Camii, yalnızca bir ibadet mekânı olarak değil, Kanuni Sultan Süleyman'ın cihanşümul hâkimiyetinin somutlaşmış ifadesi olarak tasarlandı.\"</i><br><br><b>Necipoğlu'nun bu yorumuna göre Osmanlı imparatorluk mimarisinin temel işlevi nedir?</b>",
        secenekler: [
            "A) Dini ritüellerin en verimli biçimde icra edilmesini sağlamak.",
            "B) Siyasi iktidarı ve imparatorluk prestijini görsel olarak meşrulaştırmak.",
            "C) Zanaat loncalarının ekonomik gücünü simgelemek.",
            "D) Halkın gündelik yaşamına pratik hizmet sunmak.",
            "E) Bizans mimari mirasını korumak ve sürdürmek."
        ],
        cevap: "B) Siyasi iktidarı ve imparatorluk prestijini görsel olarak meşrulaştırmak.",
        aciklama: "Metinde mimarlığın 'siyasi meşruiyetin ve imparatorluk ihtişamının görsel dili' olduğu açıkça belirtilmektedir."
    },
    {
        soru: "<i>\"Ali Kuşçu, Semerkant'tan İstanbul'a gelişiyle Osmanlı bilim ortamına yeni bir soluk getirdi. Astronomi ve matematikteki eserleri yalnızca teorik bilgi aktarmakla kalmayıp hem medrese müfredatını yeniledi hem de sonraki kuşak Osmanlı bilginleri için bir referans çerçevesi oluşturdu.\"</i><br><br><b>İhsanoğlu'nun değerlendirmesine göre Ali Kuşçu'nun Osmanlı bilim hayatına katkısı nasıl tanımlanabilir?</b>",
        secenekler: [
            "A) Doğrudan gözlem yerine spekülatif felsefeyi ön plana çıkararak medreseleri olumsuz etkiledi.",
            "B) Teorik bilgi aktarımı ve müfredat yenilenmesiyle sonraki nesil bilginlere kaynaklık etti.",
            "C) İstanbul'daki bilim geleneğini Batı Avrupa'nın etkisiyle dönüştürdü.",
            "D) Astronomiyi din ilimleri alanından ayırarak laik bir bilim dalı hâline getirdi.",
            "E) Yalnızca saray çevresinde etkili olup medrese eğitimiyle ilgilenmedi."
        ],
        cevap: "B) Teorik bilgi aktarımı ve müfredat yenilenmesiyle sonraki nesil bilginlere kaynaklık etti.",
        aciklama: "Metin, Ali Kuşçu'nun medrese müfredatını yenilediğini ve sonraki kuşaklara referans oluşturduğunu belirtmektedir."
    },
    {
        soru: "<i>\"Osmanlı külliyesi, mekânsal düzenlemesiyle toplumun pek çok gereksinimini tek bir çatı altında karşılayan çok işlevli bir yapılar topluluğuydu. Cami, medrese, imaret, kütüphane ve kervansaray gibi birimler aynı vakıf organizasyonunun parçaları olarak birlikte işlev görüyor; böylece dini, eğitsel, sosyal ve iktisadi işlevler birbirinden ayrılmaz hâle geliyordu.\"</i><br><br><b>Barkan'ın bu tespitine göre Osmanlı külliye sisteminin toplumsal işlevi hakkında hangi yorum en uygun sonucu verir?</b>",
        secenekler: [
            "A) Külliyeler yalnızca mimari ihtişam sergilemek amacıyla inşa edilmiş ve toplumsal hizmet işlevinden yoksundur.",
            "B) Külliyeler, vakıf sistemi aracılığıyla din, eğitim, ekonomi ve sosyal hizmetleri bir arada sunarak toplumsal bütünleşmeye katkıda bulunmuştur.",
            "C) Külliye sistemi, devlet bürokrasisinin genişlemesiyle birlikte vakıf gelirlerini merkezileştirmiştir.",
            "D) Osmanlı külliyelerinin temel amacı, ticaret yollarını denetim altında tutarak gümrük gelirlerini artırmaktı.",
            "E) Külliyeler yalnızca İstanbul'da gelişmiş; taşra kentlerinde benzeri yapılar kurulamamıştır."
        ],
        cevap: "B) Külliyeler, vakıf sistemi aracılığıyla din, eğitim, ekonomi ve sosyal hizmetleri bir arada sunarak toplumsal bütünleşmeye katkıda bulunmuştur.",
        aciklama: "Barkan, külliye sisteminin dini, eğitsel, sosyal ve iktisadi işlevleri tek bir vakıf çatısı altında birleştirdiğini vurgular."
    },
    {
        soru: "<i>\"Mustafa Âli, devlet hizmetinin kendisine layık görülen mevkileri sağlayamamasından duyduğu hayal kırıklığını kaleme alan tek Osmanlı entelektüeli değildi. 16. yüzyılın sonlarından itibaren eğitimli kesimlerin artan şikâyetleri, liyakat sisteminin aşınmasına ve devşirme dışından gelen grupların medrese eğitimini rütbe ve gelir kapısına dönüştürmesine işaret ediyordu.\"</i><br><br><b>Fleischer'ın bu çözümlemesine göre 16. yüzyıl sonlarında Osmanlı eğitim-bürokrasi ilişkisinde yaşanan dönüşümü en iyi açıklayan yorum hangisidir?</b>",
        secenekler: [
            "A) Medrese eğitimi giderek daha seçkin bir statü kazanmış ve bürokrasiye girişi kolaylaştırmıştır.",
            "B) Medrese, asli ilmi işlevini yitirerek bireysel kariyer çıkarlarına hizmet eden bir aşama hâline gelmeye başlamıştır.",
            "C) Devşirme sistemi, eğitimli seçkinlerin bürokratik yükselişini tamamen engellemiştir.",
            "D) Mustafa Âli, liyakat sisteminin güçlendirilmesi için reform önerileri hazırlamıştır.",
            "E) Osmanlı bürokrasisinde din adamları sınıfı güç kaybederek yerini laik memurlara bırakmıştır."
        ],
        cevap: "B) Medrese, asli ilmi işlevini yitirerek bireysel kariyer çıkarlarına hizmet eden bir aşama hâline gelmeye başlamıştır.",
        aciklama: "Fleischer, medresenin salt bir bilgi kurumu olmaktan çıkıp kariyer aracına dönüştüğünü ve liyakat sisteminin aşındığını ortaya koyar."
    },
    {
        soru: "<i>\"Sinan, her yapısında mekânsal dengeyi ve ışık kullanımını merkeze aldı. Selimiye Camii'nin tek kubbesini dört yarım kubbe yerine sekizgen payanda sistemiyle taşıması, namazgâhı görsel engellerden arındırarak iç mekânda benzersiz bir açıklık ve ferahlık duygusu yarattı.\"</i><br><br><b>Kuran'ın bu tespitine göre Sinan'ın Selimiye Camii'nde uyguladığı tasarım tercihinin temel amacı nedir?</b>",
        secenekler: [
            "A) Yapının dış cephesini olabildiğince yalın tutarak süslemeyi en aza indirmek.",
            "B) Sekizgen payanda sistemiyle iç mekânı görsel engelsiz, açık ve aydınlık bir hale getirmek.",
            "C) Bizans Ayasofya geleneğini doğrudan kopyalayarak Osmanlı mimarisini Hristiyanlık mirasıyla özdeşleştirmek.",
            "D) Yapı maliyetini düşürerek vakıf bütçesini korumak.",
            "E) İbadet kapasitesini sınırlandırarak sadece seçkin zümreye hitap etmek."
        ],
        cevap: "B) Sekizgen payanda sistemiyle iç mekânı görsel engelsiz, açık ve aydınlık bir hale getirmek.",
        aciklama: "Kuran açıkça sekizgen payanda sisteminin iç mekânda açıklık ve ferahlık yarattığını belirtmektedir."
    },
    {
        soru: "<i>\"16. yüzyıl Osmanlı düşünce ortamında heterodoks eğilimler yalnızca taşra tekke çevrelerinde değil, medrese ve saray kültürünün içinde de kendine yer bulabiliyordu. Devletin bu eğilimlere karşı tutumu tutarsızdı: Zaman zaman şiddetli bastırma politikaları uygulanırken zaman zaman da belirli dini aykırılıklar görmezden gelindi.\"</i><br><br><b>Ocak'ın bu tespiti dikkate alındığında 16. yüzyıl Osmanlı'sında dini denetim anlayışı hakkında hangi yorum en isabetli görünmektedir?</b>",
        secenekler: [
            "A) Osmanlı devleti, dini aykırılıklara karşı sistematik ve tutarlı bir hoşgörü politikası izledi.",
            "B) Heterodoks eğilimler yalnızca kırsal alanlarda görüldü; kentli elit bu tür düşüncelerden uzak kaldı.",
            "C) Dini denetim mekanizması ideolojik açıdan bütünleşik değildi; devletin tutumu bağlama göre değişkenlik gösterdi.",
            "D) Osmanlı uleması, heterodoks söylemleri sistematik biçimde yazılı kanıta dönüştürerek arşivledi.",
            "E) 16. yüzyılda medreseler dini özgürlük alanları olarak Osmanlı düşüncesinin ana merkezi hâline geldi."
        ],
        cevap: "C) Dini denetim mekanizması ideolojik açıdan bütünleşik değildi; devletin tutumu bağlama göre değişkenlik gösterdi.",
        aciklama: "Ocak, devletin tutumunun 'tutarsız' olduğunu ve bağlama göre bastırma ya da görmezden gelme biçiminde tezahür ettiğini belirtir."
    },
    {
        soru: "<i>\"Osmanlı şiir geleneğinde divan şairinin saray ile ilişkisi karmaşık bir himaye ağı üzerinde şekillendi. Şair, sultanın ya da vezirlerin hâmiliğini kazanarak hem maddi güvence elde ediyor hem de ürettiği eserle hâmisinin prestijini pekiştiriyordu. Bu karşılıklı bağımlılık, Osmanlı kültür üretiminin hem gücünü hem de sınırlılığını belirledi.\"</i><br><br><b>Emecen'in bu yorumundan hareketle Osmanlı divan edebiyatının hâmiliğe dayalı yapısını en doğru değerlendiren seçenek hangisidir?</b>",
        secenekler: [
            "A) Hâmilik sistemi şairi tamamen özgürleştirerek devlet söylemi dışında özgün yapıtlar üretmesini sağladı.",
            "B) Şair-hâmi ilişkisi, kültürel üretimi hem besleyen hem de belirli sınırlar içinde tutan karşılıklı bir bağımlılığa dayanıyordu.",
            "C) Osmanlı divan şairi, hâmiden bağımsız olarak halk kitlesine hitap eden eserler veriyordu.",
            "D) Hâmilik sistemi yalnızca 15. yüzyılda işlev gördü; 16. yüzyılda şairlerin sarayla ilişkisi koptu.",
            "E) Divan şiirinin, saray yerine medrese çevrelerinin desteğiyle varlığını sürdürdü."
        ],
        cevap: "B) Şair-hâmi ilişkisi, kültürel üretimi hem besleyen hem de belirli sınırlar içinde tutan karşılıklı bir bağımlılığa dayanıyordu.",
        aciklama: "Emecen, şair-hâmi ilişkisinin karşılıklı fayda ve bağımlılığa dayandığını; bunun hem güç hem de sınırlılık yarattığını belirtir."
    },
    {
        soru: "<i>\"17. yüzyıl başlarında Osmanlı eğitim kurumlarındaki dönüşüm, ulema sınıfının iç yapısını köklü biçimde değiştirdi. 'İltimas' ve 'rüşvet' olarak adlandırılan informel pratikler sistemin içine sızdı; bu durum medrese diplomasını gerçek ilmi yetkinliğin değil sosyal ağların göstergesine dönüştürdü.\"</i><br><br><b>Tezcan'ın bu analizine göre 17. yüzyıl başlarında Osmanlı medrese sistemindeki kurumsal gerilemenin temel nedeni nedir?</b>",
        secenekler: [
            "A) Avrupa üniversitelerinin üstün bilimsel üretimi nedeniyle medreselerin rekabet gücünü yitirmesi.",
            "B) Devletin medreselere tahsis ettiği vakıf gelirlerini keserek eğitim finansmanını doğrudan engellemesi.",
            "C) İltimas ve rüşvet gibi informel pratiklerin diplomayı bilimsel yetkinliğin değil sosyal sermayenin aracına dönüştürmesi.",
            "D) Osmanlı ulemasının Batı pozitif bilimlerine ilgi duyması ve geleneksel müfredatı terk etmesi.",
            "E) Padişahların medreseleri kapatarak eğitimi doğrudan saray çevresine taşıması."
        ],
        cevap: "C) İltimas ve rüşvet gibi informel pratiklerin diplomayı bilimsel yetkinliğin değil sosyal sermayenin aracına dönüştürmesi.",
        aciklama: "Tezcan açıkça 'iltimas' ve 'rüşvet'in diplomayı sosyal ağların göstergesine dönüştürdüğünü belirtmektedir."
    },
    {
        soru: "<i>\"Sinan, Selimiye'nin kubbesini Ayasofya kubbesiyle karşılaştırarak Osmanlı mimarlığının Hristiyan geçmişini aşıp geçtiğini iddia etti. Bu retorik, Osmanlı'nın yalnızca siyasi değil kültürel ve sanatsal açıdan da evrensel bir imparatorluk olduğunu savunma girişiminin parçasıydı.\"</i><br><br><b>Necipoğlu'nun bu yorumu ışığında Sinan'ın Ayasofya karşılaştırmasının asıl amacı nedir?</b>",
        secenekler: [
            "A) Ayasofya'yı teknik hatalar içeren yetersiz bir yapı olarak tanımlamak.",
            "B) Osmanlı mimarlığının siyasi ve kültürel egemenliğini evrensel ölçekte meşrulaştırmak.",
            "C) Bizans mimari tekniğinin Osmanlı ustalarına ilham kaynağı olduğunu kabul etmek.",
            "D) Yapı inşaatında kullanılan malzeme kalitesinin Bizans dönemiyle aynı olduğunu kanıtlamak.",
            "E) Selimiye'nin dini işlevinin Ayasofya'dan üstün olduğunu ileri sürmek."
        ],
        cevap: "B) Osmanlı mimarlığının siyasi ve kültürel egemenliğini evrensel ölçekte meşrulaştırmak.",
        aciklama: "Necipoğlu, karşılaştırmanın Osmanlı'nın evrensel siyasi ve kültürel egemenliğini meşrulaştırma retoriğinin parçası olduğunu açıkça belirtir."
    },
    {
        soru: "<i>\"Fâtih Sultan Mehmed, fethedilen İstanbul'u yalnızca bir İslam şehrine dönüştürmekle kalmayıp 'evrensel hükümdar' imgesini perçinlemek için Rum, Ermeni ve Yahudi toplulukları kente çekti. Bu çok kültürlü nüfus politikası, Osmanlı kültürel hayatını besleyen çoğulcu bir ortam yarattı.\"</i><br><br><b>İnalcık'ın bu analizine göre Fâtih'in İstanbul'u yeniden iskân politikasının kültürel hayata katkısı nasıl değerlendirilebilir?</b>",
        secenekler: [
            "A) Farklı etnik toplulukların bir arada yaşaması, Osmanlı kültürel üretimine tek tipleşme yerine çoğulcu bir zemin sağladı.",
            "B) İstanbul'daki Rum nüfus, Osmanlı İslam kültürüne dönüştürülerek asimile edildi.",
            "C) Çok kültürlü nüfus politikası yalnızca ticaret amacı güdülerek uygulandı; kültürel etkisi sınırlı kaldı.",
            "D) Ermeni ve Yahudi topluluklar, Osmanlı kültür hayatının dışında tutularak ayrı bölgelerde izole edildi.",
            "E) Fâtih'in iskân politikası, Konstantinopolis'in Hristiyan kültürel mirasını tamamen yok etmeyi hedefledi."
        ],
        cevap: "A) Farklı etnik toplulukların bir arada yaşaması, Osmanlı kültürel üretimine tek tipleşme yerine çoğulcu bir zemin sağladı.",
        aciklama: "İnalcık, farklı toplulukların kente çekilmesinin 'çoğulcu bir ortam' yarattığını belirtmektedir."
    },
    {
        soru: "<i>\"Osmanlı kent yaşamında kahvehane yalnızca bir içki mekânı değil; sohbet, müzik, şiir dinletisi ve siyasi tartışmanın odağı olarak 16. yüzyıldan itibaren saray dışında sivil bir kamusal alan oluşturdu. Bu gelişme, bazı din ve devlet adamlarının tepkisini çekse de kahvehane kültürü kalıcı hâle geldi.\"</i><br><br><b>Faroqhi'nin bu tespitine göre 16. yüzyılda Osmanlı toplumsal yaşamında kahvehanenin üstlendiği işlev en iyi nasıl tanımlanabilir?</b>",
        secenekler: [
            "A) Kahvehane, devlet kontrolündeki bir eğitim ve propaganda merkezi olarak hizmet verdi.",
            "B) Kahvehane, saray kültürünün dışında gelişen sivil bir kamusal tartışma ve kültür mekânı hâline geldi.",
            "C) Kahvehane, yalnızca tüccar sınıfına hizmet eden ticari bir buluşma yeri işlevi gördü.",
            "D) Kahvehane kültürü, Osmanlı toplumunun geleneksel dinî değerlerini pekiştiren bir kurum olarak örgütlendi.",
            "E) Kahvehane, devlet adamlarının denetimini kolaylaştırmak amacıyla bilinçli olarak tesis edildi."
        ],
        cevap: "B) Kahvehane, saray kültürünün dışında gelişen sivil bir kamusal tartışma ve kültür mekânı hâline geldi.",
        aciklama: "Faroqhi, kahvehanenin saray dışında sivil bir kamusal alan oluşturduğunu açıkça vurgular."
    },
    {
        soru: "<i>\"Osmanlı divan edebiyatı, Fars şiir geleneğini taklit etmekle kalmayıp onu yerel malzemeyle besleyerek dönüştürdü. 15. yüzyıldan itibaren Anadolu coğrafyası, toplumsal gözlemler ve Türkçe söyleyiş biçimleri divan şiirine özgün bir renk kattı; böylece kozmopolit bir estetik anlayış yerli bir kültürel kimlikle iç içe geçti.\"</i><br><br><b>Kuru'nun bu değerlendirmesine göre Osmanlı divan edebiyatının özgünlüğünü açıklayan temel etken nedir?</b>",
        secenekler: [
            "A) Farsçayı tamamen reddederek yalnızca saf Türkçe söyleyişe yönelmesi.",
            "B) Fars geleneğini yerel coğrafya, toplumsal gözlem ve Türkçe söyleyişle harmanlayarak dönüştürmesi.",
            "C) Arap şiirini model alarak Osmanlı estetiğini yeniden tanımlaması.",
            "D) Dini temaları dışlayarak dünyevi ve laik bir içeriğe odaklanması.",
            "E) Saray himayesini reddederek halk şiiri geleneğiyle bütünleşmesi."
        ],
        cevap: "B) Fars geleneğini yerel coğrafya, toplumsal gözlem ve Türkçe söyleyişle harmanlayarak dönüştürmesi.",
        aciklama: "Kuru, divan edebiyatının Fars geleneğini yerel unsurlarla harmanlayarak dönüştürdüğünü vurgular."
    },
    {
        soru: "<i>\"Osmanlı eğitim sisteminde kelam ilminin konumu, devletin dini kimliğini tanımlama çabasıyla doğrudan bağlantılıydı. Kelam dersleri, öğrencilere yalnızca teolojik bilgi sunmakla kalmayıp Osmanlı Sünni kimliğinin sınırlarını içselleştiren bir düşünce çerçevesi kazandırıyordu.\"</i><br><br><b>Al-Tikriti'nin bu yorumuna göre Osmanlı medresesinde kelam ilminin öğretilmesinin yalnızca entelektüel değil ideolojik bir işlevi olduğu düşüncesi hangi kanıtla desteklenmektedir?</b>",
        secenekler: [
            "A) Kelam derslerinin Osmanlı öğrencileri Batı felsefesine yönelterek reformcu düşünce üretmesine zemin hazırlaması.",
            "B) Kelam öğretiminin Sünni Osmanlı kimliğinin sınırlarını içselleştiren bir düşünce çerçevesi oluşturması.",
            "C) Kelam derslerinin yalnızca mesleki gereklilikten dolayı müfredata dahil edilerek teorik önemi sınırlı tutulması.",
            "D) Osmanlı medreselerinin kelam öğretiminde Şii kaynakları referans alması.",
            "E) Kelam ilminin devlet kontrolünden bağımsız olarak ulema sınıfının özerk alanı hâline gelmesi."
        ],
        cevap: "B) Kelam öğretiminin Sünni Osmanlı kimliğinin sınırlarını içselleştiren bir düşünce çerçevesi oluşturması.",
        aciklama: "Al-Tikriti, kelam öğretiminin Sünni kimlik sınırlarını içselleştiren bir çerçeve kurduğunu doğrudan belirtmektedir."
    },
    {
        soru: "<i>\"Osmanlı minyatür sanatı, 16. yüzyılın ikinci yarısından itibaren salt süsleme işlevinin ötesine geçerek tarihi olayların belgelenmesinde ve devlet propagandasının görsel dile aktarılmasında temel araç hâline geldi. Nakkaşhane'de üretilen eserler, seferleri, törenleri ve hanedanın görkemini kalıcı kılma amacı taşıyordu.\"</i><br><br><b>Artan'ın bu tespiti ışığında 16. yüzyılda Osmanlı minyatür sanatının toplumsal ve siyasi işlevi nasıl değerlendirilebilir?</b>",
        secenekler: [
            "A) Minyatür sanatı, sıradan halkın gündelik yaşamını belgelemek amacıyla nakkaşlar tarafından bağımsız olarak üretildi.",
            "B) Minyatür sanatı, devlet propagandasının ve tarihsel hafızanın görsel olarak inşa edildiği bir araç hâline geldi.",
            "C) Nakkaşhane üretimi yalnızca estetik kaygılarla yönlendirildi; siyasi içerikten uzak tutuldu.",
            "D) Osmanlı minyatür sanatı, İran ekolünü aşmayı başaramayarak özgün bir üslup geliştiremedi.",
            "E) Minyatür sanatı 17. yüzyılda gelişiminin doruğuna ulaştı ve bu dönemde devlet desteğinden bağımsızlaştı."
        ],
        cevap: "B) Minyatür sanatı, devlet propagandasının ve tarihsel hafızanın görsel olarak inşa edildiği bir araç hâline geldi.",
        aciklama: "Artan, minyatürün devlet propagandası ve tarihsel belgeleme işlevi üstlendiğini açıkça belirtir."
    }
];

window.allTests["test_u3_bilim_2"] = [
    {
        soru: "<i>\"Bilge kişi odur ki aklını peşin hükümlere değil, gerçeğin araştırılmasına harcar. Kelam tartışmalarında taraflar çoğunlukla delil yerine alışkanlık ve taklitle hareket etmiş; böylece hakikat araştırması yerini kuru münazaraya bırakmıştır. İlmin canlanması ancak tecrübe ve akıl yürütmeye dönüşle mümkün olacaktır.\"</i><br><br><b>Katip Çelebi'nin bu pasajı, 17. yüzyıl Osmanlı entelektüel dünyasının hangi temel gerilimini yansıtmaktadır?</b>",
        secenekler: [
            "A) Dini ilimlerin pozitif bilimler karşısında üstünlüğünü savunan muhafazakâr bir tutum.",
            "B) Taklit ve alışkanlığa dayalı scholastik anlayışla tecrübe ve akıl yürütmeye dayanan eleştirel düşünce arasındaki gerilim.",
            "C) Arap-Fars ilim geleneğinin Osmanlı bilim anlayışına egemenliğine karşı bir tepki.",
            "D) Osmanlı ulema sınıfının Batı bilimini sistematik biçimde benimsemesi gerektiğine dair bir çağrı.",
            "E) Dini ilimlerle dünyevi bilimlerin birbirini tümüyle dışladığına dair bir yargı."
        ],
        cevap: "B) Taklit ve alışkanlığa dayalı scholastik anlayışla tecrübe ve akıl yürütmeye dayanan eleştirel düşünce arasındaki gerilim.",
        aciklama: "Katip Çelebi, taklit ve kuru münazaraya dayalı scholastik anlayışı eleştirerek tecrübe ve akıl yürütmeyi savunmaktadır."
    },
    {
        soru: "<i>\"Osmanlı saray kültüründe sultanın şiir yazması ya da şairlere bizzat ilgi göstermesi rastlantısal bir tutku değildi. Hükümdar, şiir aracılığıyla hem dinî-ahlaki erdemi hem de insani inceliği sergiliyordu. Bu durum şairin statüsünü yükselttiği gibi şiiri de meşru bir iktidar söylemi hâline getirdi.\"</i><br><br><b>İnalcık'ın bu yorumuna göre Osmanlı sultanlarının divan şiirine ilgi göstermesinin temel işlevi nedir?</b>",
        secenekler: [
            "A) Sultanların şiiri yalnızca kişisel bir eğlence aracı olarak benimsemesi.",
            "B) Şiir aracılığıyla dini-ahlaki erdemi ve insani inceliği sergileyerek şiiri meşru bir iktidar söylemine dönüştürmek.",
            "C) Şairleri mali açıdan destekleyerek sanat piyasasını düzenlemek.",
            "D) Divan şiirinin halk kitlelerine ulaşmasını sağlamak amacıyla şiiri basitleştirmek.",
            "E) Şiiri siyasi muhalefeti denetlemenin dolaylı bir aracı olarak kullanmak."
        ],
        cevap: "B) Şiir aracılığıyla dini-ahlaki erdemi ve insani inceliği sergileyerek şiiri meşru bir iktidar söylemine dönüştürmek.",
        aciklama: "İnalcık, şiir yazmanın sultanın dini-ahlaki erdemi ve insani inceliği sergilemesini sağladığını ve şiiri meşru bir iktidar söylemine dönüştürdüğünü vurgular."
    },
    {
        soru: "<i>KAYNAK I: \"Fâtih Sultan Mehmed, ulemayı yalnızca devlet idaresinin aracı olarak görmedi; bilginin kendisini bir iktidar unsuru hâline getirdi. Sahn-ı Semân medreselerini kurarak müfredata hem nakli hem de akli bilimleri yerleştirmesi, İslam dünyasında ilmin merkezini Anadolu'ya taşıma iradesinin somut ifadesiydi.\"<br>KAYNAK II: \"Osmanlı Devleti'nin kuruluş döneminde ilim geleneği, Anadolu beyliklerinin ortamında şekillenmiş; dervişler ve alimler siyasi otoriteyle iç içe geçmiş bir kültürel zemin hazırlamıştı. Bu zemin, ilerleyen dönemde devlet eliyle kurumsallaşan eğitim düzeninin öncüsü oldu.\"</i><br><br><b>Taşköprülüzâde ve Köprülü'nün bu pasajları birlikte değerlendirildiğinde Osmanlı eğitim geleneğinin gelişimini açıklayan en kapsamlı yorum hangisidir?</b>",
        secenekler: [
            "A) Her iki kaynak da Osmanlı eğitim sisteminin Bizans ilim mirasını doğrudan devraldığını savunmaktadır.",
            "B) Taşköprülüzâde devlet eliyle kurumsallaşmaya odaklanırken Köprülü bunun öncesindeki organik kültürel zemini vurgulamakta; birlikte okunduğunda eğitim geleneğinin hem organik hem de devlet yönlendirmeli bir süreçte biçimlendiği anlaşılmaktadır.",
            "C) Köprülü Osmanlı'nın kuruluşunda alimler yerine gazi savaşçıların belirleyici olduğunu savunurken Taşköprülüzâde buna karşı çıkmaktadır.",
            "D) Her iki kaynak da Fâtih dönemiyle birlikte başlayan kurumsal eğitimin daha önceki dönemlerle hiçbir devamlılık taşımadığını ileri sürmektedir.",
            "E) Taşköprülüzâde ve Köprülü, Osmanlı eğitim sisteminin temel amacını ilmi üretimden bağımsız olarak yalnızca bürokratik kadro yetiştirmeye indirgemiştir."
        ],
        cevap: "B) Taşköprülüzâde devlet eliyle kurumsallaşmaya odaklanırken Köprülü bunun öncesindeki organik kültürel zemini vurgulamakta; birlikte okunduğunda eğitim geleneğinin hem organik hem de devlet yönlendirmeli bir süreçte biçimlendiği anlaşılmaktadır.",
        aciklama: "Taşköprülüzâde kurumsal eğitime odaklanırken Köprülü önceki organik zemini vurgular; ikisi birlikte hem organik hem yönlendirmeli bir süreci gösterir."
    },
    {
        soru: "<i>KAYNAK I: \"Osmanlı'nın kuruluş döneminde kültürel kimlik hem sınır bölgelerinin çok katmanlı toplumsal yapısından hem de farklı dinî ve etnik geleneklerin harmanlandığı bir ortamdan beslendi. Bu belirsizlik, daha sonraki klasik dönemin belirginleşen Sünni kimliğiyle gerilim yaratacaktı.\"<br>KAYNAK II: \"Kanuni dönemiyle birlikte Osmanlı siyasi kültürü Süleymani bir imparatorluk ideolojisi etrafında kristalleşti. Süleymaniye Camii, bu ideolojinin taşa kazınmış ifadesiydi: Cihan hükümdarı aynı zamanda İslam'ın hâmisi ve adaletin simgesiydi.\"</i><br><br><b>Kafadar ve Necipoğlu'nun değerlendirmeleri birlikte okunduğunda Osmanlı kültürel kimliğinin 15. yüzyıl başlarından 16. yüzyıl ortasına değin geçirdiği dönüşüm hakkında hangi yorum ortaya çıkmaktadır?</b>",
        secenekler: [
            "A) Her iki yazar da Osmanlı kültürel kimliğinin kuruluştan itibaren değişmeden kaldığını savunmaktadır.",
            "B) Kafadar'a göre erken dönemde çok katmanlı ve belirsiz bir kimlik hâkimken Necipoğlu'na göre Kanuni döneminde bu kimlik İslami imparatorluk ideolojisi etrafında kristalleşmiştir; bu iki süreç birlikte okunduğunda kimliğin çatışmalı dinamikler içinde pekiştiği anlaşılır.",
            "C) Necipoğlu, erken dönem kimlik belirsizliğini Kafadar'dan farklı olarak olumlu bir çoğulculuk olarak yorumlamaktadır.",
            "D) Her iki metin de mimarinin kültürel kimlik üzerindeki etkisini yetersiz bulmakta ve edebi geleneği öne çıkarmaktadır.",
            "E) Kafadar ve Necipoğlu Osmanlı kimliğinin tamamen yapay ve siyasi güdümlü olduğu görüşünde birleşmektedir."
        ],
        cevap: "B) Kafadar'a göre erken dönemde çok katmanlı ve belirsiz bir kimlik hâkimken Necipoğlu'na göre Kanuni döneminde bu kimlik İslami imparatorluk ideolojisi etrafında kristalleşmiştir; bu iki süreç birlikte okunduğunda kimliğin çatışmalı dinamikler içinde pekiştiği anlaşılır.",
        aciklama: "Kafadar erken dönemin çok katmanlı ve belirsiz kimliğini anlatırken Necipoğlu Kanuni döneminde bu kimliğin İslami imparatorluk ideolojisi etrafında kristalleştiğini göstermektedir."
    },
    {
        soru: "<i>KAYNAK I: \"Cihannümâ'yı kaleme alırken yalnızca İslam coğrafyacılarının eserlerine değil Batılı coğrafya kitaplarına da başvurdum; zira bilgiyi yalnızca bir geleneğe hapsederek hakikate ulaşmak mümkün değildir. Batı'nın deniz keşiflerinden elde ettiği bilgi birikimini görmezden gelmek, bilginin kendisine ihanet olurdu.\"<br>KAYNAK II: \"17. yüzyıl Osmanlı bilginleri, Avrupa bilimsel devriminin ürettiklerini fark etmeye başlamış; ancak bu bilgilerin sistematik biçimde müfredata entegrasyonu kurumsal direnç nedeniyle gecikmiştir. Katip Çelebi bu geçiş döneminin sembolik figürü olarak öne çıkmaktadır.\"</i><br><br><b>Her iki kaynak birlikte değerlendirildiğinde 17. yüzyıl Osmanlı bilim dünyasının Batı bilimiyle ilişkisini en doğru açıklayan yorum hangisidir?</b>",
        secenekler: [
            "A) Osmanlı bilginleri Batı bilimini bütünüyle reddetti; sistematik bir diyaloğun varlığına dair kanıt bulunmamaktadır.",
            "B) Katip Çelebi gibi aydınların bireysel girişimleriyle Batı bilgisine açılma eğilimi belirirse de kurumsal düzeyde sistematik entegrasyon sağlanamadı; bu durum teorik açıklık ile kurumsal direnç arasındaki derin gerilimi yansıtmaktadır.",
            "C) Her iki kaynak da Osmanlı Devleti'nin 17. yüzyılda Avrupa bilimiyle tam anlamıyla bütünleştiğini ve bu sürecin medrese reformlarıyla desteklendiğini göstermektedir.",
            "D) İhsanoğlu, Katip Çelebi'nin Batı bilimi konusundaki tutumunun kurumsallaşma açısından başarılı olduğunu savunurken Katip Çelebi bunu açık biçimde reddetmektedir.",
            "E) Her iki metinde de Batı biliminin Osmanlı'ya aktarımının yalnızca tercüme faaliyetleriyle gerçekleştiği ileri sürülmektedir."
        ],
        cevap: "B) Katip Çelebi gibi aydınların bireysel girişimleriyle Batı bilgisine açılma eğilimi belirirse de kurumsal düzeyde sistematik entegrasyon sağlanamadı; bu durum teorik açıklık ile kurumsal direnç arasındaki derin gerilimi yansıtmaktadır.",
        aciklama: "Katip Çelebi'nin metni bireysel entelektüel açıklığı, İhsanoğlu'nun metni ise kurumsal direnci ortaya koymaktadır. Birlikte okunduğunda teorik açıklık ile kurumsal entegrasyon başarısızlığı arasındaki gerilim belirginleşmektedir."
    },
    {
        soru: "<i>\"Osmanlı eğitim sisteminde müderris, medresenin yalnızca hocası değil aynı zamanda o müessesenin itibarını ve bilimsel geleneğini taşıyan kişiydi. Müderrisin şöhreti, öğrencilerin hangi medreseyi tercih edeceğini doğrudan belirler; böylece kişisel bilgi otoritesi kurumsal itibarla iç içe geçerdi.\"</i><br><br><b>İnalcık'ın bu değerlendirmesine göre Osmanlı medreselerinin itibarı hangi temel etken üzerine kuruluydu?</b>",
        secenekler: [
            "A) Devlet tarafından belirlenen standart müfredata bağlılık.",
            "B) Müderrisin kişisel bilim otoritesi ve şöhretinin kurumsal itibarla özdeşleşmesi.",
            "C) Vakıf gelirlerinin büyüklüğü ve mali güç.",
            "D) Padişah fermanıyla resmen onaylanan kurumsal statü.",
            "E) Medresenin hangi şehirde konumlandığı."
        ],
        cevap: "B) Müderrisin kişisel bilim otoritesi ve şöhretinin kurumsal itibarla özdeşleşmesi.",
        aciklama: "Metin açıkça müderrisin şöhretinin tercih kararını belirlediğini ve kişisel bilgi otoritesinin kurumsal itibarla iç içe geçtiğini belirtmektedir."
    },
    {
        soru: "<i>\"Osmanlı medrese mimarisinde avlunun merkeziliği tesadüfi değildi. Revaklı avlu; öğrencilerin hem ders takip ettiği hem de arkadaşlarıyla ilmi tartışma yürüttüğü bir sosyal-eğitimsel mekân olarak işlev gördü. Mimari düzenleme, ilmin bireysel değil topluluk temelli bir etkinlik olduğu anlayışını fiziksel olarak somutlaştırdı.\"</i><br><br><b>Kuran'ın bu yorumuna göre Osmanlı medrese mimarisinde avlunun merkezi konumu ne anlama gelir?</b>",
        secenekler: [
            "A) Avlu, öğrencileri ders dışı zamanlarda dışarıyla temasını kesmek için tasarlanmıştır.",
            "B) Mimari düzenleme, ilmin bireysel değil topluluk temelli ve sosyal bir etkinlik olduğunu fiziksel olarak yansıtmaktadır.",
            "C) Avlu, vakıf gelirlerini artırmak amacıyla dükkânlara dönüştürülen bir ticari alan olarak kullanılmıştır.",
            "D) Medrese mimarisi, Bizans manastır geleneğinin doğrudan bir devamı olarak tasarlanmıştır.",
            "E) Revaklı avlu, yalnızca tören ve resmi toplantılar için ayrılmış temsili bir mekândı."
        ],
        cevap: "B) Mimari düzenleme, ilmin bireysel değil topluluk temelli ve sosyal bir etkinlik olduğunu fiziksel olarak yansıtmaktadır.",
        aciklama: "Kuran, avlunun hem dersler hem tartışmalar için kullanıldığını ve mimari düzenlemenin ilmin topluluk temelli olduğu anlayışını somutlaştırdığını belirtmektedir."
    },
    {
        soru: "<i>\"Osmanlı hamamı, yalnızca bedensel temizlik mekânı olarak değil, farklı toplumsal kesimlerin bir arada bulunabildiği sosyal bir toplanma yeri olarak da değerlendirilmelidir. Hem erkekler hem kadınlar için ayrılmış bölümleri olan hamam, kentsel dokuda toplumsal kaynaşmayı kolaylaştıran nadir kamusal mekânlardan biriydi.\"</i><br><br><b>Faroqhi'nin bu yorumuna göre Osmanlı hamamının kentsel yaşamdaki işlevi nasıl tanımlanabilir?</b>",
        secenekler: [
            "A) Hamam, yalnızca üst gelir gruplarına hizmet eden lüks bir mekândı.",
            "B) Hamam, bedensel temizliğin ötesinde farklı toplumsal kesimlerin bir arada bulunduğu sosyal bir kamusal mekân işlevi gördü.",
            "C) Osmanlı hamamı, dini ritüellerin icra edildiği cami ile eş değer bir ibadet alanıydı.",
            "D) Hamam, yalnızca saray çevresindeki elitlerin kullandığı özel bir mekândı.",
            "E) Hamam, vakıf sisteminden bağımsız olarak belediye idaresince işletilen ticari bir tesis niteliğindeydi."
        ],
        cevap: "B) Hamam, bedensel temizliğin ötesinde farklı toplumsal kesimlerin bir arada bulunduğu sosyal bir kamusal mekân işlevi gördü.",
        aciklama: "Faroqhi, hamamın 'kentsel dokuda toplumsal kaynaşmayı kolaylaştıran nadir kamusal mekânlardan biri' olduğunu açıkça belirtmektedir."
    },
    {
        soru: "<i>\"Osmanlı'da tekke eğitimi, medrese eğitimiyle hem rekabet hem de tamamlayıcılık ilişkisi içindeydi. Medrese aklî ve nakli bilimleri öğretirken tekke, müridin manevi-pratik eğitimini üstlendi. Bu iki kurumun birlikte işlev görmesi, Osmanlı toplumunun entelektüel ve dinî hayatını çoğulcu bir yapıda tuttu.\"</i><br><br><b>Ocak'ın bu değerlendirmesine göre Osmanlı eğitim sisteminde medrese ve tekke ilişkisini en doğru tanımlayan çerçeve hangisidir?</b>",
        secenekler: [
            "A) Medrese ve tekke birbirini tamamen dışlayan kurumlar olup Osmanlı toplumunda sürekli çatışma içindeydi.",
            "B) Medrese ve tekke, farklı işlevleriyle tamamlayıcı bir ilişki kurarak Osmanlı entelektüel ve dinî hayatını çoğulcu biçimde besledi.",
            "C) Osmanlı devleti, tekkeleri medreselerin alt birimi olarak kurumsallaştırdı ve denetim altında tuttu.",
            "D) Tekke eğitimi, yalnızca kırsal kesimlerde işlev görürken medreseler kentsel alanlarda egemen oldu.",
            "E) 17. yüzyılda medreseler tekkeleri tamamen ortadan kaldırarak eğitim alanında tekelleşti."
        ],
        cevap: "B) Medrese ve tekke, farklı işlevleriyle tamamlayıcı bir ilişki kurarak Osmanlı entelektüel ve dinî hayatını çoğulcu biçimde besledi.",
        aciklama: "Ocak, medrese ve tekkenin hem rekabetçi hem tamamlayıcı bir ilişki içinde olduğunu ve birlikte işleyerek çoğulcu bir yapı oluşturduğunu belirtmektedir."
    },
    {
        soru: "<i>\"Kanuni döneminde Osmanlı sanat ve mimarisinde bir 'klasik sentez' arayışı belirginleşti. Bu sentez, İslam sanatının birikimini Osmanlı'nın İslam dünyasına liderliğini meşrulaştırmak için yeniden düzenleyen bilinçli bir estetik politikanın ürünüydü. Sanat, artık yalnızca beğeni meselesi değil bir devlet söylemi hâline gelmişti.\"</i><br><br><b>Necipoğlu'nun bu yorumuna göre Kanuni döneminde Osmanlı sanatının 'klasik sentez' arayışı nasıl değerlendirilebilir?</b>",
        secenekler: [
            "A) Sanatçıların bireysel estetik tercihleri doğrultusunda kendiliğinden gelişen bir akım olarak ortaya çıkmıştır.",
            "B) Osmanlı'nın İslam dünyasında liderliğini meşrulaştırmaya yönelik bilinçli bir estetik politika ve devlet söylemi olarak biçimlenmiştir.",
            "C) Batı Rönesans sanatının Osmanlı'ya uyarlanması girişiminin bir ürünüdür.",
            "D) Klasik sentez, ticaret yolları üzerinden İran sanatının Osmanlı'ya aktarılmasının bir yansımasıdır.",
            "E) Sarayın estetik tercihlerinden bağımsız biçimde loncaların yönlendirdiği bir zanaat geleneğinin ürünüdür."
        ],
        cevap: "B) Osmanlı'nın İslam dünyasında liderliğini meşrulaştırmaya yönelik bilinçli bir estetik politika ve devlet söylemi olarak biçimlenmiştir.",
        aciklama: "Necipoğlu, klasik sentezin 'bilinçli bir estetik politikanın ürünü' ve 'devlet söylemi' olduğunu açıkça belirtmektedir."
    },
    {
        soru: "<i>\"Osmanlı coğrafya bilgisinin gelişimi, deniz seferlerinin genişlemesiyle doğrudan bağlantılıydı. Piri Reis'in Kitab-ı Bahriye'si, teorik bilginin deneyimle harmanlandığı; matematiksel çizim tekniklerinin pratik seyir bilgisiyle birleştirildiği özgün bir örnek oluşturuyordu. Bu eser, coğrafya biliminin Osmanlı'da salt edebi bir tür olmaktan çıkıp uygulamalı bir disipline dönüştüğünün göstergesiydi.\"</i><br><br><b>İhsanoğlu'nun bu değerlendirmesine göre Piri Reis'in Kitab-ı Bahriye'sinin Osmanlı bilim tarihindeki önemi nedir?</b>",
        secenekler: [
            "A) Kitap, coğrafya bilgisini yalnızca edebî biçimde sunan ve pratik değerden yoksun bir eserdir.",
            "B) Eser, teorik bilgi ile deneyimsel pratiği birleştirerek coğrafyayı uygulamalı bir disipline dönüştürmüştür.",
            "C) Piri Reis, Batı Avrupalı denizcilerin harita tekniklerini doğrudan Osmanlı'ya aktarmıştır.",
            "D) Kitab-ı Bahriye, Osmanlı coğrafya geleneğinin İslam dünyasına tümüyle bağımlı kaldığını ortaya koymaktadır.",
            "E) Eser, yalnızca sultan için üretilmiş olup hiçbir pratik seyir değeri taşımamıştır."
        ],
        cevap: "B) Eser, teorik bilgi ile deneyimsel pratiği birleştirerek coğrafyayı uygulamalı bir disipline dönüştürmüştür.",
        aciklama: "İhsanoğlu, Kitab-ı Bahriye'nin teorik bilgiyi deneyimle harmanlayarak coğrafyayı uygulamalı bir disipline dönüştürdüğünü açıkça belirtmektedir."
    },
    {
        soru: "<i>\"Kanuni Sultan Süleyman'ın 'kanun koyucu' imgesi, salt hukuki bir düzenleme meselesinin ötesinde evrensel meşruiyet iddiasıyla örülmüştü. Bu imge, Osmanlı'nın Avrupa'daki Hristiyan imparatorluk geleneğiyle ve İslam dünyasındaki halifelik söylemiyle aynı anda rekabet ettiği karmaşık bir ideolojik alanı yansıtıyordu.\"</i><br><br><b>Fleischer'ın bu tespitine göre Kanuni dönemi Osmanlı ideolojisinin temel özelliği nedir?</b>",
        secenekler: [
            "A) Osmanlı ideolojisi, yalnızca İslam halifeliği geleneğine dayanarak özgünlüğünü korudu.",
            "B) Osmanlı ideolojisi, eş zamanlı olarak Hristiyan imparatorluk geleneğiyle ve İslam halifeliğiyle rekabet eden çok katmanlı bir evrensellik iddiasına sahipti.",
            "C) Kanuni dönemi Osmanlı ideolojisi, hukuki düzenlemeleri diğer tüm meşruiyet iddialarının önüne geçirdi.",
            "D) Osmanlı'nın ideolojik söylemi, Avrupa ve İslam dünyasıyla rekabetten kaçınarak özgün bir yol izledi.",
            "E) Kanuni'nin kanun koyucu imgesi, yalnızca iç siyasete yönelik bir meşruiyet aracı olarak işlev gördü."
        ],
        cevap: "B) Osmanlı ideolojisi, eş zamanlı olarak Hristiyan imparatorluk geleneğiyle ve İslam halifeliğiyle rekabet eden çok katmanlı bir evrensellik iddiasına sahipti.",
        aciklama: "Fleischer, Kanuni döneminin eş zamanlı olarak Hristiyan imparatorluk geleneği ve İslam halifelik söylemiyle rekabet eden çok katmanlı evrensel meşruiyet iddiasına dayandığını belirtmektedir."
    },
    {
        soru: "<i>\"Osmanlı saray törenleri, siyasi hiyerarşiyi simgesel düzeyde yeniden üreten karmaşık birer performanstı. Payitahtta düzenlenen bayram divanları, elçi kabulü ve sünnet düğünleri, yalnızca eğlence değil; kim kimin yanında, hangi sırayla, nasıl oturduğunun titizlikle kurgulandığı iktidar gösterileri olarak işlev görüyordu.\"</i><br><br><b>Artan'ın bu yorumuna göre Osmanlı saray törenlerinin temel işlevi nedir?</b>",
        secenekler: [
            "A) Törenler, halkın eğlencesine yönelik gösterilerdi ve siyasi içerikten yoksundu.",
            "B) Törenler, siyasi hiyerarşiyi simgesel olarak yeniden üreten ve iktidar ilişkilerini görünür kılan yapılandırılmış performanslardı.",
            "C) Osmanlı saray törenleri, Avrupa saray geleneğinden doğrudan alınmıştı ve Osmanlı özgünlüğünden yoksundu.",
            "D) Törenler, yalnızca dini amaçlarla düzenleniyor ve siyasi içerikleri ikincil planda kalıyordu.",
            "E) Saray törenlerinin katı bir düzeni yoktu; her törenin biçimi katılımcıların insiyatifine bırakılıyordu."
        ],
        cevap: "B) Törenler, siyasi hiyerarşiyi simgesel olarak yeniden üreten ve iktidar ilişkilerini görünür kılan yapılandırılmış performanslardı.",
        aciklama: "Artan, törenlerin 'siyasi hiyerarşiyi simgesel düzeyde yeniden üreten' yapılandırılmış iktidar gösterileri olduğunu açıkça belirtmektedir."
    },
    {
        soru: "<i>\"Osmanlı âlim sınıfı, ulema olarak anılmakla birlikte monolitik bir yapı sergilemiyordu. Müderristen kadıya, müftüden imam-hatibe kadar uzanan hiyerarşik düzlemde farklı uzmanlıklar, farklı kurumsal bağlantılar ve farklı toplumsal ağlar işlev görüyordu. Bu çeşitlilik, ulemanın devletle ilişkisini de çok boyutlu kılıyordu.\"</i><br><br><b>Atçıl'ın bu tespitiyle bağdaşan Osmanlı ulema sınıfı değerlendirmesi hangisidir?</b>",
        secenekler: [
            "A) Osmanlı uleması, tek tip bir ideolojik konumdan hareket eden homojen bir sınıftı.",
            "B) Ulema, farklı uzmanlıklar ve kurumsal bağlantılarla iç içe geçmiş heterojen bir yapı oluşturarak devletle çok boyutlu bir ilişki kuruyordu.",
            "C) Osmanlı ulema sınıfı, devlet karşısında daima otonom ve muhalif bir tutum sergiledi.",
            "D) Ulema içindeki hiyerarşik düzlem, üyeler arasında toplumsal ağ kurulmasını sistematik biçimde engelledi.",
            "E) Müderrisler ve kadılar arasındaki sınır o denli keskin çizilmişti ki aralarında hiçbir hareketlilik yaşanmıyordu."
        ],
        cevap: "B) Ulema, farklı uzmanlıklar ve kurumsal bağlantılarla iç içe geçmiş heterojen bir yapı oluşturarak devletle çok boyutlu bir ilişki kuruyordu.",
        aciklama: "Atçıl, ulemanın monolitik olmadığını; farklı uzmanlık ve bağlantılarla heterojen bir yapı oluşturduğunu belirtmektedir."
    },
    {
        soru: "<i>\"Taşra şehirlerinde kurulan medreseler yalnızca İstanbul'daki hiyerarşiye bağlı taşınabilir bir bilgi aktarımının aracı değildi. Manisa, Edirne ve Bursa gibi merkezlerde gelişen medrese gelenekleri, yerel kültürel birikim ve bölgesel alimler zinciri aracılığıyla özgün bir entelektüel kimlik inşa etti.\"</i><br><br><b>Emecen'in bu tespitine göre Osmanlı taşra medreselerinin entelektüel önemi nasıl değerlendirilebilir?</b>",
        secenekler: [
            "A) Taşra medreseleri yalnızca İstanbul merkezli bilginin kopyalanması işlevi gördü; özgün üretimden yoksundu.",
            "B) Taşra medreseleri, yerel kültürel birikim ve bölgesel alimler aracılığıyla özgün entelektüel kimlikler oluşturdu.",
            "C) Osmanlı taşra medreseleri, kırsalda çalışmak istemeyen başarısız öğrencilerin son tercihi hâline geldi.",
            "D) Taşra medreseleri, İstanbul ile aralarında olası rekabeti önlemek amacıyla devlet tarafından kapatıldı.",
            "E) Osmanlı eğitim sistemi, taşrada yalnızca din eğitimi veren sıbyan mekteplerini destekledi; medreselere yer vermedi."
        ],
        cevap: "B) Taşra medreseleri, yerel kültürel birikim ve bölgesel alimler aracılığıyla özgün entelektüel kimlikler oluşturdu.",
        aciklama: "Emecen, taşra medreselerinin 'özgün bir entelektüel kimlik inşa ettiğini' açıkça belirtmektedir."
    }
];

window.allTests["test_u3_bilim_3"] = [
    {
        soru: "<i>\"Kanuni döneminin 'altın çağ' olarak idealize edilmesi, Osmanlı tarih yazımında geriye dönük bir mükemmelleştirme sürecinin ürünüydü. Bu idealizasyon, 16. yüzyılın sonlarından itibaren yaşanan krizleri anlamlandırmaya çalışan aydınlar ve bürokratlar tarafından bilinçli ya da bilinçsiz biçimde kurgulandı.\"</i><br><br><b>Kafadar'ın bu yorumuna göre Osmanlı tarih yazımındaki 'altın çağ' kavramının işlevi nasıl açıklanabilir?</b>",
        secenekler: [
            "A) Altın çağ kavramı, Kanuni döneminin nesnel olarak üstünlüğünü belgeleyen tarafsız bir tarih analizi ürünüdür.",
            "B) Altın çağ idealizasyonu, ilerleyen dönemlerde yaşanan krizleri anlamlandırmak için geriye dönük olarak kurgulanan ideolojik bir araçtır.",
            "C) Kanuni döneminin mükemmelliği döneme ait belgelerle tamamen kanıtlanmış olup tarih yazımı bunu doğru aktarmaktadır.",
            "D) Altın çağ kavramı yalnızca Osmanlı dışındaki kaynaklarda ortaya çıkmış; Osmanlı aydınları bu idealizasyona katılmamıştır.",
            "E) Kafadar'a göre altın çağ söylemi, devletin propagandasından tamamen bağımsız biçimde halk kültüründe oluşmuştur."
        ],
        cevap: "B) Altın çağ idealizasyonu, ilerleyen dönemlerde yaşanan krizleri anlamlandırmak için geriye dönük olarak kurgulanan ideolojik bir araçtır.",
        aciklama: "Kafadar, altın çağ kavramının 'geriye dönük mükemmelleştirme' sürecinin ürünü olduğunu ve kriz dönemlerinde anlam üretme aracı işlevi gördüğünü belirtmektedir."
    },
    {
        soru: "<i>\"Fâtih Sultan Mehmed'in saray kitaplığı yalnızca İslam yazmaları koleksiyonundan ibaret değildi. Yunanca ve Latince metinlere de yer verilmesi, Fâtih'in kendisini yalnızca İslam medeniyetinin değil antik Yunan-Roma mirasının da varisi olarak konumlandırma çabası olarak okunabilir. Bu entelektüel çoğulculuk, Fâtih'in evrensel hükümdar imgesinin kültürel boyutunu oluşturuyordu.\"</i><br><br><b>Raby'nin bu yorumuna göre Fâtih'in saray kitaplığındaki Yunanca ve Latince eserlerin bulunması ne anlama gelmektedir?</b>",
        secenekler: [
            "A) Fâtih, İslam medeniyetine olan bağlılığını zayıflatarak Hristiyan kültürüne yaklaşmaya çalışıyordu.",
            "B) Fâtih, hem İslam medeniyetinin hem de Yunan-Roma mirasının varisi olma iddiasıyla evrensel hükümdar imgesini kültürel çoğulculukla pekiştiriyordu.",
            "C) Saray kitaplığındaki Batı eserleri, yalnızca diplomatik hediyeler olup içerikleriyle ilgilenilmiyordu.",
            "D) Yunanca ve Latince eserler, tercüme faaliyetleri için birer hammadde kaynağı olarak kullanıldı ve metinlerin orijinal içerikleri önemsenmedi.",
            "E) Fâtih, Bizans'ın entelektüel birikimini kendi kültürel kimliğini kurmak yerine yok etmek amacıyla topluyordu."
        ],
        cevap: "B) Fâtih, hem İslam medeniyetinin hem de Yunan-Roma mirasının varisi olma iddiasıyla evrensel hükümdar imgesini kültürel çoğulculukla pekiştiriyordu.",
        aciklama: "Raby, Fâtih'in Yunanca-Latince eserlere sahip çıkmasını evrensel hükümdar imgesinin kültürel boyutu ve entelektüel çoğulculuk olarak yorumlamaktadır."
    },
    {
        soru: "<i>\"17. yüzyılın başlarında bazı Osmanlı aydın ve bürokratları, devletin zayıflamasını ahlaki çöküşe bağlayan 'nasihat' edebiyatı ürettiler. Bu eserler, 'kanun-ı kadim' ya da ataların yolunun terk edildiği gerekçesiyle kurumsal reformların kaçınılmazlığını savunuyordu. Ancak nasihat yazarlarının önerdiği reform, çoğunlukla geçmişi yeniden inşa etme biçiminde tasavvur edildi.\"</i><br><br><b>Tezcan'ın bu yorumuna göre 17. yüzyıl Osmanlı nasihat edebiyatının sınırlılığı nedir?</b>",
        secenekler: [
            "A) Nasihat edebiyatı, köklü kurumsal dönüşümler yerine geçmişin idealize biçimine dönüşü hedeflediğinden yapısal bir çözüm sunmakta yetersiz kaldı.",
            "B) Nasihat yazarları, devletin zayıflamasını ekonomik nedenlere bağlayarak ahlaki söylemden tamamen kaçındı.",
            "C) Nasihat edebiyatı, reform yerine mevcut düzeni koruyan muhafazakâr bir tutum benimsedi ve değişime tamamen karşı çıktı.",
            "D) 17. yüzyıl nasihat yazarları, Avrupa kurumlarını model alarak köklü modernleşme önerileri sundu.",
            "E) Nasihat edebiyatı yalnızca saray çevresinde üretildi ve toplumun geniş kesimlerine hiç ulaşmadı."
        ],
        cevap: "A) Nasihat edebiyatı, köklü kurumsal dönüşümler yerine geçmişin idealize biçimine dönüşü hedeflediğinden yapısal bir çözüm sunmakta yetersiz kaldı.",
        aciklama: "Tezcan, nasihat yazarlarının reformu çoğunlukla 'geçmişi yeniden inşa etme' biçiminde tasavvur ettiğini belirtmektedir; bu da yapısal çözüm sunmayı kısıtlamaktadır."
    },
    {
        soru: "<i>\"Heterodoks derviş gruplarının Osmanlı kültür coğrafyasındaki varlığı, devletin kurumsal İslam anlayışıyla zaman zaman gerginleşen canlı bir kültürel çoğulculuğa işaret ediyordu. Bu gruplar özellikle kuruluş döneminin sınır bölgelerinde hem manevi otorite hem de toplumsal kaynaşma işlevi üstlendi.\"</i><br><br><b>Karamustafa'nın bu tespiti dikkate alındığında Osmanlı kuruluş dönemindeki kültürel çoğulculuk ile klasik dönem Sünni ortodoksisi arasındaki ilişkiyi en doğru yorumlayan seçenek hangisidir?</b>",
        secenekler: [
            "A) Kuruluş döneminin kültürel çoğulculuğu, klasik dönemde de değişmeden sürdü; Sünni ortodoksi hiçbir zaman egemen olmadı.",
            "B) Kuruluş döneminin çoğulcu ortamı, klasik dönemde devletin Sünni ortodoksiyi kurumsallaştırmasıyla gerilim yaratacak bir yapı taşıdı.",
            "C) Heterodoks derviş grupları, devletin baskısı karşısında tamamen ortadan kalktı ve klasik dönemde hiçbir izleri kalmadı.",
            "D) Karamustafa, Osmanlı kültürel çoğulculuğunun yalnızca Anadolu'dan bağımsız dış etkilerden kaynaklandığını savunmaktadır.",
            "E) Osmanlı devleti, kuruluştan itibaren heterodoks grupları destekleyerek Sünni ortodoksiye açıkça karşı çıktı."
        ],
        cevap: "B) Kuruluş döneminin çoğulcu ortamı, klasik dönemde devletin Sünni ortodoksiyi kurumsallaştırmasıyla gerilim yaratacak bir yapı taşıdı.",
        aciklama: "Karamustafa, heterodoks grupların devletin kurumsal İslam anlayışıyla 'zaman zaman gerginleşen' bir çoğulculuğu temsil ettiğini belirtmektedir."
    },
    {
        soru: "<i>\"Osmanlı sultanı yalnızca siyasi ve askeri bir komutan değil aynı zamanda şer'i hukuku yerine getiren ve İslam'ı koruyan 'din-ü devlet'in önderi olarak tanımlandı. Bu ikili meşruiyet, hem 'gazi' geleneğini hem de 'halife' geleneğini bünyesinde barındırıyor; böylece sultanın otoritesini İslam dünyasının tamamına yönelik bir talebe dönüştürüyordu.\"</i><br><br><b>İnalcık'ın bu yorumuna göre Osmanlı sultan otoritesinin 'ikili meşruiyet' yapısı nasıl tanımlanabilir?</b>",
        secenekler: [
            "A) Osmanlı sultanı, aynı anda hem Batı Hristiyan imparatorluk geleneğini hem de İslam halifeliğini temsil eden ikili bir kimlik taşıdı.",
            "B) Osmanlı sultan otoritesi, gazi savaşçı geleneği ile İslam'ın hâmisi olma iddiasını bir araya getirerek evrensel bir İslami meşruiyet inşa etti.",
            "C) Osmanlı sultanının meşruiyeti yalnızca askeri başarıya dayanıyordu; dini otorite sınırlı bir rol oynadı.",
            "D) Osmanlı'nın ikili meşruiyet yapısı, 16. yüzyılda tamamen çökerek yalnızca şer'i otoriteye indirgendi.",
            "E) Osmanlı sultanlığı, gazi geleneğini 16. yüzyılda terk ederek salt bir İslam halifeliği modeline geçti."
        ],
        cevap: "B) Osmanlı sultan otoritesi, gazi savaşçı geleneği ile İslam'ın hâmisi olma iddiasını bir araya getirerek evrensel bir İslami meşruiyet inşa etti.",
        aciklama: "İnalcık, gazi ve halife geleneklerinin bir arada taşındığını ve bu ikili yapının sultanın otoritesini İslam dünyasının tamamına yönelik evrensel bir talebe dönüştürdüğünü belirtmektedir."
    },
    {
        soru: "<i>\"16. ve 17. yüzyıl Osmanlı el sanatları, hem iç talebi hem de uluslararası ticareti besleyen yüksek kaliteli üretim merkezleriydi. İznik çiniciliği ve Bursa ipeklisi gibi ürünler, Avrupa saraylarında ve İslam dünyasında aranan mallar hâline geldi. Bu üretim, Osmanlı'nın yalnızca siyasi değil ekonomik ve estetik açıdan da cihan ölçeğinde etkili bir güç olduğunu kanıtlıyordu.\"</i><br><br><b>Faroqhi'nin bu tespitine göre Osmanlı el sanatlarının uluslararası talep görmesinin tarihsel önemi nedir?</b>",
        secenekler: [
            "A) Osmanlı el sanatları yalnızca iç tüketime yönelik üretildi; uluslararası ticaret bu sektörde ikincil bir role sahipti.",
            "B) Osmanlı el sanatlarının uluslararası talep görmesi, Osmanlı'nın estetik ve ekonomik etki alanının küresel ölçeğini ortaya koymaktadır.",
            "C) İznik çiniciliği ve Bursa ipeklisi, yalnızca saray siparişleri üzerine üretilen ve piyasaya sunulmayan ürünlerdi.",
            "D) Osmanlı el sanatlarının uluslararası başarısı, Batı Avrupa zanaatkârlarının teknoloji transferinin bir ürünüydü.",
            "E) Osmanlı hükümeti, el sanatları ihracatını kısıtlayarak iç piyasayı koruma altına aldı."
        ],
        cevap: "B) Osmanlı el sanatlarının uluslararası talep görmesi, Osmanlı'nın estetik ve ekonomik etki alanının küresel ölçeğini ortaya koymaktadır.",
        aciklama: "Faroqhi, Osmanlı el sanatlarının Avrupa ve İslam dünyasında aranan mallar haline geldiğini ve Osmanlı'nın estetik ve ekonomik açıdan da cihan ölçeğinde etkili olduğunu belirtmektedir."
    },
    {
        soru: "<i>\"Osmanlı vezirlerinin ve üst bürokratlarının eğitim patronajı, devletin resmî eğitim kurumlarını desteklemesinin ötesinde kişisel nüfuz alanı oluşturmanın da bir aracıydı. Medrese veya kütüphane yaptırmak, hamam inşa etmek ya da şairlere maaş bağlamak, hem dindarlığı hem de siyasi güveni somutlaştıran yatırımlar olarak değerlendirildi.\"</i><br><br><b>Kunt'un bu tespitine göre Osmanlı üst bürokrasisinin eğitim ve kültür patronajını yalnızca hayırseverlik olarak açıklamak neden yetersiz kalır?</b>",
        secenekler: [
            "A) Çünkü patronaj faaliyetleri devlet bütçesinden değil kişisel servetlerden finanse ediliyordu.",
            "B) Çünkü eğitim ve kültür patronajı, hayırseverliğin yanı sıra kişisel nüfuz ve siyasi güven inşasının da bir aracıydı.",
            "C) Çünkü vezirlerin eğitim patronajı yalnızca zorunlu bir vergi yükümlülüğünün yerine getirilmesiydi.",
            "D) Çünkü 16. yüzyılda Osmanlı bürokrasisinde eğitime ilgi duyan tek yetkili Sadrazamlar grubuydu.",
            "E) Çünkü kültür patronajı, verimsiz bir yatırım olarak vizir sınıfı tarafından genel olarak reddedildi."
        ],
        cevap: "B) Çünkü eğitim ve kültür patronajı, hayırseverliğin yanı sıra kişisel nüfuz ve siyasi güven inşasının da bir aracıydı.",
        aciklama: "Kunt, patronajın hem dindarlık (hayırseverlik) hem de siyasi güven ve nüfuz alanı oluşturmanın bir aracı olduğunu belirtmektedir."
    },
    {
        soru: "<i>KAYNAK I: \"Osmanlı minyatür sanatı, 16. yüzyıldan itibaren toplumsal yaşamın çeşitli boyutlarını—bayramları, seferleri, esnaf alaylarını—görsel olarak kayıt altına aldı. Bu eserler, hem resmi tarih yazımının görsel tamamlayıcısı hem de dönemin toplumsal coğrafyasına ilişkin değerli bir kaynak işlevi görmektedir.\"<br>KAYNAK II: \"Osmanlı geometrik süsleme sanatı, matematiği estetikle buluşturan özgün bir görsel dil geliştirdi. Topkapı Sarayı'nın mimarisinden halı tasarımlarına kadar uzanan bu gelenek, zanaatkârın bir hesapçı ve teknisyen olduğu kadar entelektüel bir yaratıcı olduğunu da ortaya koymaktadır.\"</i><br><br><b>Her iki kaynak birlikte değerlendirildiğinde 16. yüzyıl Osmanlı görsel kültürünü en kapsamlı biçimde açıklayan yorum hangisidir?</b>",
        secenekler: [
            "A) Her iki kaynak da Osmanlı görsel kültürünün salt dekoratif amaçla üretildiğini ve siyasi ya da entelektüel içerikten yoksun olduğunu ileri sürmektedir.",
            "B) Faroqhi görsel kültürü toplumsal bellek ve tarihsel belge işleviyle tanımlarken Necipoğlu matematiği estetikle harmanlayan entelektüel bir yaratıcılık boyutunu ortaya koymakta; birlikte okunduğunda Osmanlı görsel kültürünün belge, propaganda ve entelektüel üretim işlevlerini aynı anda taşıdığı anlaşılmaktadır.",
            "C) Faroqhi ve Necipoğlu, Osmanlı görsel kültürünün yalnızca saray patronajıyla beslendiğinde yaratıcılık sergilediğini birlikte savunmaktadır.",
            "D) Her iki metin de Osmanlı görsel kültürünün Batı sanatından ilham alarak geliştiğini ve özgün bir sentez üretemediğini göstermektedir.",
            "E) Faroqhi toplumsal yaşamı belgeleyen minyatürlerin bilimsel değerini kabul ederken Necipoğlu geometrik süslemenin yalnızca zanaat düzeyinde kaldığını savunmaktadır."
        ],
        cevap: "B) Faroqhi görsel kültürü toplumsal bellek ve tarihsel belge işleviyle tanımlarken Necipoğlu matematiği estetikle harmanlayan entelektüel bir yaratıcılık boyutunu ortaya koymakta; birlikte okunduğunda Osmanlı görsel kültürünün belge, propaganda ve entelektüel üretim işlevlerini aynı anda taşıdığı anlaşılmaktadır.",
        aciklama: "Faroqhi minyatürü belge ve toplumsal kayıt işleviyle ele alırken Necipoğlu geometrik süslemenin matematiksel-entelektüel boyutunu ortaya koymaktadır. Birlikte okunduğunda çok boyutlu bir kültürel üretim anlaşılır."
    },
    {
        soru: "<i>KAYNAK I: \"Osmanlı'nın Avrupa karşısındaki askeri ve siyasi etkinliği, dönemin bilim ve teknik alanındaki yenilenme kapasitesiyle doğrudan bağlantılıydı. Topçuluk ve mühendislik bilgisinin devşirilmesi, yalnızca askeri bir tercih değil, imparatorluğun var olma koşulu hâline gelmişti.\"<br>KAYNAK II: \"17. yüzyıla gelindiğinde Osmanlı'nın Avrupa ordularıyla rekabeti teknik bilgi aktarımında ciddi bir gecikme sorununu da beraberinde getiriyordu. Bu gecikme, askeri yenilgilerden çok kurumsal atalete ve bürokratik dirençlere bağlanabilir.\"</i><br><br><b>İnalcık ve Murphey'in değerlendirmeleri birlikte okunduğunda Osmanlı bilim ve teknik kapasitesinin yükselen dönemden 17. yüzyıla değin geçirdiği dönüşümü açıklayan en kapsamlı yorum hangisidir?</b>",
        secenekler: [
            "A) Her iki kaynak da Osmanlı'nın teknik bilgi üretimini dönem boyunca istikrarlı biçimde sürdürdüğünü ve hiçbir gerileme yaşanmadığını ortaya koymaktadır.",
            "B) İnalcık'a göre erken dönemde yenilenme kapasitesi Osmanlı'nın varlığını sürdürmesini sağlarken Murphey 17. yüzyılda bu kapasitenin kurumsal atalet nedeniyle gerilediğini göstermektedir; iki kaynak birlikte okunduğunda teknik dinamizmin yerini giderek kurumsal pekişmeye bıraktığı anlaşılmaktadır.",
            "C) Murphey, Osmanlı askeri gerilemenin yalnızca Avrupa ordularının üstün teknik kapasitesinden kaynaklandığını savunurken İnalcık bu iddiayı reddeder.",
            "D) Her iki kaynak da 17. yüzyıl Osmanlı askeri gerilemenin temel nedenini mali krizlere bağlamaktadır.",
            "E) İnalcık ve Murphey, Osmanlı bilimsel kapasitesinin askeri alandan bağımsız geliştiğini ve ikisi arasında sistematik bir ilişki bulunmadığını birlikte ileri sürmektedir."
        ],
        cevap: "B) İnalcık'a göre erken dönemde yenilenme kapasitesi Osmanlı'nın varlığını sürdürmesini sağlarken Murphey 17. yüzyılda bu kapasitenin kurumsal atalet nedeniyle gerilediğini göstermektedir; iki kaynak birlikte okunduğunda teknik dinamizmin yerini giderek kurumsal pekişmeye bıraktığı anlaşılmaktadır.",
        aciklama: "İnalcık erken dönemde teknik yenilenmenin varlık koşulu olduğunu belirtirken Murphey 17. yüzyılda gecikmenin kurumsal atalet ve bürokratik dirençle açıklanabileceğini göstermektedir."
    },
    {
        soru: "<i>KAYNAK I: \"Osmanlı'nın İslam anlayışı, yalnızca Arap veya Acem İslam'ının bir kopyası değildi. Türkmen heterodoks geleneklerinden beslenmiş, şehir merkezlerinde kurumsallaşmış Sünni İslam ile halk kültüründeki sufi pratiklerin bileşimi Osmanlı'ya özgü karma bir dini kimlik yarattı.\"<br>KAYNAK II: \"Osmanlı'nın kuruluş kültüründe 'Müslüman' ve 'Hristiyan' kimliklerinin sınırları günümüzdeki kadar keskin değildi. Sınır bölgelerinde kimlik geçişkenliği ve senkretizm, siyasi bütünleşmeyi kolaylaştıran araçlara dönüştü.\"</i><br><br><b>Ocak ve Kafadar'ın bu pasajları birlikte okunduğunda Osmanlı'nın dini kimlik anlayışına ilişkin hangi genel sonuca ulaşılabilir?</b>",
        secenekler: [
            "A) Her iki yazar da Osmanlı dini kimliğinin kuruluştan itibaren homojen ve katı bir Sünni ortodoksiye dayandığını savunmaktadır.",
            "B) Ocak, Osmanlı dini kimliğinin karma ve çok katmanlı yapısına dikkat çekerken Kafadar kuruluş dönemindeki kimlik geçişkenliğini vurgulamakta; birlikte okunduğunda Osmanlı dini kimliğinin ne salt orthodoks ne de salt senkretik olmayan dinamik ve bağlama göre şekillenen bir süreç olduğu anlaşılmaktadır.",
            "C) Her iki yazar da Osmanlı dini kimliğinin yalnızca Türkmen heterodoks geleneğinden beslendiğini ve Sünni kurumsallaşmanın bu geleneği temelden değiştirdiğini ileri sürmektedir.",
            "D) Kafadar, sınır bölgelerindeki kimlik geçişkenliğinin Osmanlı'nın Sünni kimliğini güçlendirdiğini savunurken Ocak bunun tam tersi bir etkisi olduğunu öne sürmektedir.",
            "E) Ocak ve Kafadar, Osmanlı İslam anlayışının başından itibaren diğer medeniyetlerle senkretik bir sentez oluşturduğunu ve bu durumun siyasi açıdan hiçbir sorun yaratmadığını birlikte ileri sürmektedir."
        ],
        cevap: "B) Ocak, Osmanlı dini kimliğinin karma ve çok katmanlı yapısına dikkat çekerken Kafadar kuruluş dönemindeki kimlik geçişkenliğini vurgulamakta; birlikte okunduğunda Osmanlı dini kimliğinin ne salt orthodoks ne de salt senkretik olmayan dinamik ve bağlama göre şekillenen bir süreç olduğu anlaşılmaktadır.",
        aciklama: "Ocak karma ve çok katmanlı dini kimliği, Kafadar ise kuruluş dönemindeki kimlik geçişkenliğini vurgulamaktadır. Birlikte okunduğunda dinamik ve karmaşık bir kimlik inşası süreci görülür."
    },
    {
        soru: "<i>\"Fatih Sultan Mehmed, İstanbul'u fethettikten sonra şehri yalnızca siyasi değil, entelektüel bir merkeze dönüştürmeyi hedefledi. Sarayına Rum, İtalyan ve Müslüman bilginleri davet etti; dönemin önde gelen filozoflarıyla tartışmalar düzenledi. Farsça ve Rumca öğrenen Fatih, Bizans'ın miras bıraktığı kütüphane geleneğini devralmak ve İstanbul'u İslam dünyasının yeni bilim başkenti yapmak istiyordu.\"</i><br><br><b>İnalcık'ın bu değerlendirmesine göre Fatih'in kültür politikasının temel özelliği nedir?</b>",
        secenekler: [
            "A) Yalnızca Müslüman bilginleri destekleyerek saf bir İslam bilim merkezi kurmak",
            "B) Farklı medeniyetlerden bilim insanlarını bir araya getirerek çok kültürlü bir entelektüel ortam oluşturmak",
            "C) Bizans kütüphanelerini devlet mülkü ilan ederek kamuya açık eğitim kurumlarına dönüştürmek",
            "D) Batılı bilim anlayışını İstanbul'a aktarmak için yalnızca İtalyan bilginlere öncelik vermek",
            "E) Siyasi meşruiyetini güçlendirmek amacıyla dini bilim çevrelerini himayesi altına almak"
        ],
        cevap: "B) Farklı medeniyetlerden bilim insanlarını bir araya getirerek çok kültürlü bir entelektüel ortam oluşturmak",
        aciklama: "Metinde Fatih'in Rum, İtalyan ve Müslüman bilginleri bir arada sarayında bulundurduğu, farklı diller öğrendiği ve Bizans'ın entelektüel mirasını devralmak istediği vurgulanmaktadır. Bu çok kültürlü yaklaşım B seçeneğiyle doğrudan örtüşür."
    },
    {
        soru: "<i>\"Osmanlı medrese sistemi, yalnızca dini ilimleri değil; matematik, astronomi, mantık ve felsefe gibi aklî bilimleri de müfredatına katmıştır. Danişmend ve müderris arasındaki uzun öğrenim süreci, bilginin yalnızca aktarılmasını değil, özümsenmesini de amaçlıyordu. Medresenin vakfa bağlı yapısı sayesinde eğitim devlet denetiminden büyük ölçüde bağımsız biçimde sürdürülmüştür.\"</i><br><br><b>Uzunçarşılı'nın bu analizine göre Osmanlı medreselerinin belirleyici özelliği nedir?</b>",
        secenekler: [
            "A) Eğitimi yalnızca din adamı yetiştirmeye odaklayan dar bir müfredat uygulamak",
            "B) Hem aklî hem naklî ilimleri kapsayan, vakıf güvencesiyle özerk bir eğitim anlayışı sunmak",
            "C) Yalnızca İstanbul'daki büyük medreselerde kaliteli eğitim vermek",
            "D) Devlet denetiminde olan sıkı bir müfredat programıyla standart bilgi aktarmak",
            "E) Öğrencileri yalnızca idari kadrolar için hazırlayan pratik bir meslek okulu işlevi görmek"
        ],
        cevap: "B) Hem aklî hem naklî ilimleri kapsayan, vakıf güvencesiyle özerk bir eğitim anlayışı sunmak",
        aciklama: "Metin üç önemli özelliği açıkça vurgular: aklî ve naklî bilimlerin birlikte okutulması, özümseme hedefi ve vakfa bağlı özerk yapı. B seçeneği bunları kapsar."
    },
    {
        soru: "<i>\"Mimar Sinan'ın eserleri, Osmanlı mimarisini salt bir inşa pratiğinden çıkararak bütünlüklü bir mimari dilin ifadesine dönüştürmüştür. Sinan, kubbenin mekânsal kapasitesini sistematik biçimde deneyen ilk mimar olup her büyük yapıta yeni bir çözüm getirmiştir. Şehzade Camii'nden Süleymaniye'ye, oradan Selimiye'ye uzanan gelişim çizgisi, salt tekrar değil bilinçli bir mesleki olgunlaşmanın izlerini taşır.\"</i><br><br><b>Necipoğlu'nun bu değerlendirmesine göre Sinan'ın mimari anlayışındaki temel ilerleme nedir?</b>",
        secenekler: [
            "A) Her yapıda aynı planı uygulayarak Osmanlı mimarisinde tutarlılık sağlamak",
            "B) Kubbeyi her yapıtta yeniden yorumlayarak mimari dili deney ve olgunlaşmayla geliştirmek",
            "C) Bizans mimarisini birebir kopyalayarak İslam medeniyetine aktarmak",
            "D) Yalnızca dini yapılar inşa ederek sultanın dinî otoritesini pekiştirmek",
            "E) Mimari tekniği Batı'dan ithal ederek Osmanlı yapım geleneğini dönüştürmek"
        ],
        cevap: "B) Kubbeyi her yapıtta yeniden yorumlayarak mimari dili deney ve olgunlaşmayla geliştirmek",
        aciklama: "Necipoğlu metni, Sinan'ın her yapıtta kubbe mekânını yeniden denediğini ve bunun bilinçli bir mesleki olgunlaşma olduğunu vurgular."
    },
    {
        soru: "<i>\"Semerkandlı astronom Ali Kuşçu, 1472'de Fatih'in daveti üzerine İstanbul'a geldi. Uzun ve zahmetli bir yolculuğun ardından sarayda coşkuyla karşılanan bilgin, sultana bir astronomi risalesi armağan etti. Ali Kuşçu, İstanbul'daki medreselerde ders verdi ve Osmanlı bilim çevrelerinde Semerkand'ın matematiksel astronomi geleneğini yaşattı. Onun İstanbul'a gelmesi, Osmanlı coğrafyasındaki bilimsel üretimin Orta Asya kökleriyle bağını yeniden kurdu.\"</i><br><br><b>Babinger'in anlatısından hareketle Ali Kuşçu'nun Osmanlı bilim tarihindeki önemi nasıl değerlendirilebilir?</b>",
        secenekler: [
            "A) Astronomiyi dini ilimler hiyerarşisinden çıkararak Osmanlı medreselerinde bağımsız bir disiplin haline getirmesi",
            "B) Osmanlı biliminin Orta Asya kökleriyle bağını yenileyerek matematiksel astronomi geleneğini İstanbul'a aktarması",
            "C) Fatih'e siyasi danışman olarak hizmet ederek Osmanlı dış politikasını bilimsel temele oturtması",
            "D) Avrupa astronomisini İslam bilimiyle sentezleyerek tamamen özgün bir Osmanlı astronomi okulu kurması",
            "E) Mısır ve Suriye'deki Müslüman bilim geleneğini İstanbul'a taşıyarak medrese müfredatını yenilemesi"
        ],
        cevap: "B) Osmanlı biliminin Orta Asya kökleriyle bağını yenileyerek matematiksel astronomi geleneğini İstanbul'a aktarması",
        aciklama: "Metin Ali Kuşçu'nun Semerkand'ın matematiksel astronomi geleneğini yaşattığını ve Orta Asya kökleriyle bağı yeniden kurduğunu belirtmektedir."
    },
    {
        soru: "<i>\"Piri Reis'in 1513 tarihli dünya haritası yalnızca bir coğrafya eseri değildir; Osmanlı denizcilik bilgisinin derleyici ve eleştirel bir sentezini temsil eder. Piri Reis, Portekiz kaptanlarından ele geçirilen haritaları, İslam coğrafya geleneğini ve kendi seferlerinden elde ettiği gözlemleri bir arada değerlendirmiştir. Bu yöntem, tek bir otoriteye bağlı kalmayan, kaynakları sorgulayan ve karşılaştıran bir bilgi anlayışına işaret eder.\"</i><br><br><b>Faroqhi'nin bu analizine göre Piri Reis'in haritacılık yaklaşımı hangi bilgi anlayışını yansıtmaktadır?</b>",
        secenekler: [
            "A) Geleneksel İslam coğrafyasına sıkı sıkıya bağlı kalarak Batılı kaynakları dışlayan muhafazakâr bir yöntem",
            "B) Farklı kültürlerden elde edilen bilgileri eleştirel bir süzgeçten geçirerek sentezleyen çoğulcu bir bilgi anlayışı",
            "C) Osmanlı deniz kuvvetlerinin askeri ihtiyaçlarına yanıt veren tamamen pratik bir coğrafya anlayışı",
            "D) Portekiz kaynaklarını merkeze alarak Osmanlı denizciliğini Batı'ya bağımlı kılan bir aktarım modeli",
            "E) Kişisel gözlemi tüm diğer kaynakların üzerinde tutan ampirist bir bilim felsefesi"
        ],
        cevap: "B) Farklı kültürlerden elde edilen bilgileri eleştirel bir süzgeçten geçirerek sentezleyen çoğulcu bir bilgi anlayışı",
        aciklama: "Metin Piri Reis'in Portekiz haritalarını, İslam geleneğini ve kendi gözlemlerini 'sorgulayan ve karşılaştıran' eleştirel bir sentezle birleştirdiğini belirtmektedir."
    }
];
